// Pictor — Compact + Indirect Draw Generation Shader (§7.2 Step 4)
// Compacts visible objects and generates DrawIndexedIndirectCommand entries.
// Uses atomic counter for the draw count.

#version 450

layout(local_size_x = 256) in;

layout(set = 0, binding = 0) uniform CompactParams {
    uint objectCount;
    uint indexCountPerMesh;   // For 1M Spheres: 240 (80 tri * 3)
    uint baseVertex;
    uint firstIndex;
};

// Input: visibility flags from cull pass
layout(std430, set = 0, binding = 1) readonly buffer Visibility {
    uint gpu_visibility[];
};

// Input: mesh info (for multi-mesh support)
layout(std430, set = 0, binding = 2) readonly buffer MeshInfo {
    // x = indexCount, y = firstIndex, z = baseVertex, w = meshId
    uvec4 gpu_mesh_info[];
};

// Output: DrawIndexedIndirectCommand (§7.3)
struct DrawCommand {
    uint indexCount;
    uint instanceCount;
    uint firstIndex;
    int  vertexOffset;
    uint firstInstance;
};

layout(std430, set = 0, binding = 3) writeonly buffer IndirectDrawBuffer {
    DrawCommand drawCommands[];
};

// Atomic draw count
layout(std430, set = 0, binding = 4) buffer DrawCountBuffer {
    uint drawCount;
};

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    if (gpu_visibility[idx] != 0) {
        // Atomically allocate a slot in the indirect draw buffer
        uint drawIdx = atomicAdd(drawCount, 1);

        // For the 1M Spheres benchmark, all objects share the same mesh
        // so we create one draw command per visible object (instanced as batch)
        drawCommands[drawIdx].indexCount    = indexCountPerMesh;
        drawCommands[drawIdx].instanceCount = 1;
        drawCommands[drawIdx].firstIndex    = firstIndex;
        drawCommands[drawIdx].vertexOffset  = int(baseVertex);
        drawCommands[drawIdx].firstInstance = idx; // gl_InstanceIndex = object index
    }
}

// Pictor — GPU Frustum + Hi-Z Culling Shader (§7.2, §10.3)
// Tests each object's AABB against frustum planes and Hi-Z depth buffer.
// Output: per-object visibility flag.

#version 450

layout(local_size_x = 256) in;

layout(set = 0, binding = 0) uniform CullParams {
    vec4  frustumPlanes[6]; // xyz = normal, w = distance
    mat4  viewProj;
    uint  objectCount;
    uint  enableHiZ;       // 0 = frustum only, 1 = frustum + Hi-Z
    float hiZWidth;
    float hiZHeight;
};

// Input: AABB bounds
layout(std430, set = 0, binding = 1) readonly buffer Bounds {
    vec4 gpu_bounds[]; // pairs: [min, max]
};

// Output: visibility flags
layout(std430, set = 0, binding = 2) writeonly buffer Visibility {
    uint gpu_visibility[];
};

// Hi-Z depth pyramid (optional)
layout(set = 0, binding = 3) uniform sampler2D hiZTexture;

bool frustumCull(vec3 aabbMin, vec3 aabbMax) {
    for (int i = 0; i < 6; i++) {
        vec3 normal = frustumPlanes[i].xyz;
        float dist  = frustumPlanes[i].w;

        // Test positive vertex (the vertex most in the direction of the plane normal)
        vec3 pVertex;
        pVertex.x = (normal.x > 0.0) ? aabbMax.x : aabbMin.x;
        pVertex.y = (normal.y > 0.0) ? aabbMax.y : aabbMin.y;
        pVertex.z = (normal.z > 0.0) ? aabbMax.z : aabbMin.z;

        if (dot(normal, pVertex) + dist < 0.0) {
            return false; // Outside this plane
        }
    }
    return true;
}

bool hiZOcclusionCull(vec3 aabbMin, vec3 aabbMax) {
    if (enableHiZ == 0) return true; // Hi-Z disabled, pass through

    // Project AABB corners to screen space
    vec4 corners[8];
    corners[0] = viewProj * vec4(aabbMin.x, aabbMin.y, aabbMin.z, 1.0);
    corners[1] = viewProj * vec4(aabbMax.x, aabbMin.y, aabbMin.z, 1.0);
    corners[2] = viewProj * vec4(aabbMin.x, aabbMax.y, aabbMin.z, 1.0);
    corners[3] = viewProj * vec4(aabbMax.x, aabbMax.y, aabbMin.z, 1.0);
    corners[4] = viewProj * vec4(aabbMin.x, aabbMin.y, aabbMax.z, 1.0);
    corners[5] = viewProj * vec4(aabbMax.x, aabbMin.y, aabbMax.z, 1.0);
    corners[6] = viewProj * vec4(aabbMin.x, aabbMax.y, aabbMax.z, 1.0);
    corners[7] = viewProj * vec4(aabbMax.x, aabbMax.y, aabbMax.z, 1.0);

    // Find screen-space bounding rectangle and closest depth
    float minZ = 1.0;
    vec2 minXY = vec2(1.0);
    vec2 maxXY = vec2(0.0);

    for (int i = 0; i < 8; i++) {
        if (corners[i].w <= 0.0) return true; // Behind camera, don't cull

        vec3 ndc = corners[i].xyz / corners[i].w;
        vec2 uv = ndc.xy * 0.5 + 0.5;

        minXY = min(minXY, uv);
        maxXY = max(maxXY, uv);
        minZ = min(minZ, ndc.z);
    }

    // Determine Hi-Z mip level based on screen-space size
    vec2 screenSize = (maxXY - minXY) * vec2(hiZWidth, hiZHeight);
    float mipLevel = ceil(log2(max(screenSize.x, screenSize.y)));
    mipLevel = clamp(mipLevel, 0.0, 10.0);

    // Sample Hi-Z at corners of the screen-space rect
    float hiZDepth = textureLod(hiZTexture, (minXY + maxXY) * 0.5, mipLevel).r;

    // If the object is behind the Hi-Z depth, it's occluded
    return minZ <= hiZDepth;
}

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    vec3 aabbMin = gpu_bounds[idx * 2].xyz;
    vec3 aabbMax = gpu_bounds[idx * 2 + 1].xyz;

    bool visible = frustumCull(aabbMin, aabbMax);

    if (visible && enableHiZ != 0) {
        visible = hiZOcclusionCull(aabbMin, aabbMax);
    }

    gpu_visibility[idx] = visible ? 1u : 0u;
}

// Pictor — Compute Update Shader (§5.4, §14.3)
// Updates gpu_transforms and gpu_bounds for all GPU Driven objects.
// 1 thread = 1 object. Dispatch: ceil(objectCount / 256) workgroups.
//
// For the 1M Spheres benchmark, objects follow 3D Lissajous curves.
// Input: initial positions, frequency/phase params, frame constants.
// Output: updated transforms (float4x4) and bounds (AABB).

#version 450

layout(local_size_x = 256) in;

// Frame constants (§5.4: ~64B uniform, uploaded each frame)
layout(set = 0, binding = 0) uniform UpdateParams {
    float totalTime;
    float deltaTime;
    uint  frameNumber;
    float gravity;
    uint  objectCount;
    float amplitude;
    float pad0, pad1;
};

// Input SSBOs
layout(std430, set = 0, binding = 1) readonly buffer InitialPositions {
    vec4 initialPos[]; // xyz = position, w = radius
};

layout(std430, set = 0, binding = 2) readonly buffer FreqPhase {
    // xy = freqX, freqY; zw = freqZ, phaseX
    // Second vec4: xy = phaseY, phaseZ; zw = unused
    vec4 freqPhaseData[];
};

// Output SSBOs (§7.3)
layout(std430, set = 0, binding = 3) writeonly buffer Transforms {
    mat4 gpu_transforms[];
};

layout(std430, set = 0, binding = 4) writeonly buffer Bounds {
    // AABB: vec4(min.xyz, 0), vec4(max.xyz, 0)
    vec4 gpu_bounds[];
};

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    // Read initial position and radius
    vec4 initP = initialPos[idx];
    vec3 basePos = initP.xyz;
    float radius = initP.w;

    // Read frequency and phase parameters (§14.3)
    vec4 fp0 = freqPhaseData[idx * 2];
    vec4 fp1 = freqPhaseData[idx * 2 + 1];
    float freqX  = fp0.x;
    float freqY  = fp0.y;
    float freqZ  = fp0.z;
    float phaseX = fp0.w;
    float phaseY = fp1.x;
    float phaseZ = fp1.y;

    // 3D Lissajous curve motion (§14.3)
    vec3 pos;
    pos.x = basePos.x + amplitude * sin(totalTime * freqX + phaseX);
    pos.y = basePos.y + amplitude * sin(totalTime * freqY + phaseY);
    pos.z = basePos.z + amplitude * sin(totalTime * freqZ + phaseZ);

    // Write transform (translation matrix)
    mat4 transform = mat4(1.0);
    transform[3] = vec4(pos, 1.0);
    gpu_transforms[idx] = transform;

    // Write AABB (§14.3: sphere bounding box)
    gpu_bounds[idx * 2]     = vec4(pos - vec3(radius), 0.0);
    gpu_bounds[idx * 2 + 1] = vec4(pos + vec3(radius), 0.0);
}

// Pictor — Projected Decal
// シーン深度からワールド座標を復元し、 デカールの OBB 内かどうかを判定して
// ボックスのローカル UV でテクスチャをサンプルし、 シーンカラーへブレンド
// する。 fullscreen_quad.vert と組で使う。 ブレンドモード (Alpha/Additive/
// Multiply) は呼び出し側のパイプラインで切り替える。

#version 450

layout(location = 0) in  vec2 inUV;     // 0..1 (画面座標。 左上原点)
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform Scene {
    mat4 inv_view_proj;   // 深度 → ワールド座標 復元用
};
layout(set = 0, binding = 1) uniform sampler2D depthTex;   // シーン深度
layout(set = 1, binding = 0) uniform sampler2D decalTex;   // デカール画像

layout(push_constant) uniform PC {
    mat4  inv_decal;      // inverse(decal world transform)
    float opacity;
    float angle_fade;     // 投影面の角度フェード閾値 (0 で無効)
    float depth_fade;     // OBB Y 端のフェード幅
    float _pad0;
    vec4  decal_axis;     // xyz = デカールの投影軸 (ワールド空間, 正規化済み)
};

void main() {
    float depth = texture(depthTex, inUV).r;   // Vulkan depth [0,1]
    if (depth >= 1.0) discard;                 // 背景 = サーフェス無し

    // 画面 UV + depth → NDC → ワールド座標
    vec2 ndc = inUV * 2.0 - 1.0;               // Vulkan: y は下向き
    vec4 clip = vec4(ndc, depth, 1.0);
    vec4 worldH = inv_view_proj * clip;
    vec3 world  = worldH.xyz / worldH.w;

    // デカールローカル空間へ。 OBB は [-0.5, 0.5]^3。
    vec3 local = (inv_decal * vec4(world, 1.0)).xyz;
    vec3 a = abs(local);
    if (a.x > 0.5 || a.y > 0.5 || a.z > 0.5) discard;

    // ローカル XZ をデカール UV に。
    vec2 uv = local.xz + 0.5;
    vec4 d = texture(decalTex, uv);

    // OBB の Y 端でフェード (depth_fade 幅)。
    float dfade = 1.0 - smoothstep(0.5 - max(depth_fade, 1e-4), 0.5, a.y);

    // 投影面の角度フェード: サーフェス法線を深度の微分から再構成し、
    // デカール投影軸との一致度が低い (= 横向きの面) ほどフェードする。
    float afade = 1.0;
    if (angle_fade > 0.0) {
        vec3 dWx = dFdx(world);
        vec3 dWy = dFdy(world);
        vec3 surf_n = normalize(cross(dWx, dWy));
        float facing = abs(dot(surf_n, normalize(decal_axis.xyz)));
        afade = smoothstep(0.0, angle_fade, facing);
    }

    float alpha = d.a * opacity * dfade * afade;
    if (alpha <= 0.0) discard;
    outColor = vec4(d.rgb, alpha);   // ブレンドはパイプライン側
}

// Pictor — Global Illumination Probe Sampling Shader
// Computes indirect diffuse lighting by sampling irradiance probes
// placed on a uniform 3D grid. Produces an irradiance map that
// material shaders can sample without coupling to the GI algorithm.
//
// Approach: Light Probe Grid (similar to DDGI — Dynamic Diffuse GI)
//   1. Each probe stores SH coefficients or cubemap irradiance
//   2. This shader interpolates nearby probes for each visible object
//   3. Output: per-object indirect diffuse SH (L2 spherical harmonics)

#version 450

layout(local_size_x = 256) in;

layout(set = 0, binding = 0) uniform GIProbeParams {
    vec4  gridOrigin;         // xyz = world-space origin of probe grid
    vec4  gridSpacing;        // xyz = spacing between probes
    uvec4 gridDimensions;     // xyz = probe count per axis, w = total
    uint  objectCount;
    uint  probeCount;
    float giIntensity;        // global multiplier for indirect light
    float maxProbeDistance;   // max distance for probe influence
};

// Input: world-space transforms (translation = object position)
layout(std430, set = 0, binding = 1) readonly buffer Transforms {
    mat4 gpu_transforms[];
};

// Input: object visibility flags
layout(std430, set = 0, binding = 2) readonly buffer Visibility {
    uint gpu_visibility[];
};

// Input: probe irradiance data — L2 SH coefficients (9 vec4 per probe)
// Each probe: 9 × vec4 = 36 floats = RGB irradiance in SH basis
layout(std430, set = 0, binding = 3) readonly buffer ProbeIrradiance {
    vec4 probe_sh[];  // [probeIdx * 9 + shCoeff]
};

// Output: per-object indirect diffuse (L2 SH, 9 × vec4 per object)
layout(std430, set = 0, binding = 4) writeonly buffer ObjectIrradiance {
    vec4 object_irradiance[];  // [objIdx * 9 + shCoeff]
};

// Convert world position to probe grid index
ivec3 worldToProbeIndex(vec3 worldPos) {
    vec3 local = (worldPos - gridOrigin.xyz) / gridSpacing.xyz;
    return ivec3(floor(local));
}

// Flatten 3D probe index to 1D
uint probeIndex3Dto1D(ivec3 idx) {
    return uint(idx.z) * gridDimensions.x * gridDimensions.y
         + uint(idx.y) * gridDimensions.x
         + uint(idx.x);
}

// Check if probe index is valid
bool isValidProbe(ivec3 idx) {
    return idx.x >= 0 && idx.y >= 0 && idx.z >= 0 &&
           uint(idx.x) < gridDimensions.x &&
           uint(idx.y) < gridDimensions.y &&
           uint(idx.z) < gridDimensions.z;
}

// Trilinear interpolation of 8 surrounding probes' SH data
void interpolateProbes(vec3 worldPos, out vec4 resultSH[9]) {
    // Initialize output
    for (int i = 0; i < 9; i++) {
        resultSH[i] = vec4(0.0);
    }

    vec3 local = (worldPos - gridOrigin.xyz) / gridSpacing.xyz;
    ivec3 baseIdx = ivec3(floor(local));
    vec3 frac = local - vec3(baseIdx);

    float totalWeight = 0.0;

    // Sample 8 corners of the surrounding cell
    for (int dz = 0; dz < 2; dz++) {
        for (int dy = 0; dy < 2; dy++) {
            for (int dx = 0; dx < 2; dx++) {
                ivec3 probeIdx = baseIdx + ivec3(dx, dy, dz);

                if (!isValidProbe(probeIdx)) continue;

                // Trilinear weight
                vec3 w = mix(1.0 - frac, frac, vec3(dx, dy, dz));
                float weight = w.x * w.y * w.z;

                if (weight <= 0.0) continue;

                uint flatIdx = probeIndex3Dto1D(probeIdx);

                // Distance-based falloff
                vec3 probeWorld = gridOrigin.xyz + vec3(probeIdx) * gridSpacing.xyz;
                float dist = length(worldPos - probeWorld);
                float distWeight = 1.0 - smoothstep(0.0, maxProbeDistance, dist);
                weight *= distWeight;

                if (weight <= 0.0) continue;

                // Accumulate SH coefficients
                for (int s = 0; s < 9; s++) {
                    resultSH[s] += probe_sh[flatIdx * 9 + s] * weight;
                }
                totalWeight += weight;
            }
        }
    }

    // Normalize
    if (totalWeight > 0.0) {
        float invWeight = 1.0 / totalWeight;
        for (int i = 0; i < 9; i++) {
            resultSH[i] *= invWeight;
        }
    }
}

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    // Skip invisible objects
    if (gpu_visibility[idx] == 0) {
        for (int i = 0; i < 9; i++) {
            object_irradiance[idx * 9 + i] = vec4(0.0);
        }
        return;
    }

    // Extract world position from transform matrix
    vec3 worldPos = gpu_transforms[idx][3].xyz;

    // Interpolate irradiance from surrounding probes
    vec4 sh[9];
    interpolateProbes(worldPos, sh);

    // Apply global GI intensity
    for (int i = 0; i < 9; i++) {
        object_irradiance[idx * 9 + i] = sh[i] * giIntensity;
    }
}

// Pictor — Hi-Z Mipmap Build Shader (§10.3)
// Generates hierarchical depth buffer from the depth pre-pass output.
// Each mip level stores the maximum depth of its 2x2 parent region.

#version 450

layout(local_size_x = 16, local_size_y = 16) in;

layout(set = 0, binding = 0) uniform HiZParams {
    uvec2 inputSize;
    uvec2 outputSize;
    uint  mipLevel;
};

layout(set = 0, binding = 1) uniform sampler2D inputDepth;
layout(set = 0, binding = 2, r32f) writeonly uniform image2D outputDepth;

void main() {
    uvec2 pos = gl_GlobalInvocationID.xy;
    if (pos.x >= outputSize.x || pos.y >= outputSize.y) return;

    // Sample 2x2 texels from the previous mip level
    vec2 texelSize = 1.0 / vec2(inputSize);
    vec2 uv = (vec2(pos) * 2.0 + 0.5) * texelSize;

    float d0 = textureLodOffset(inputDepth, uv, float(mipLevel), ivec2(0, 0)).r;
    float d1 = textureLodOffset(inputDepth, uv, float(mipLevel), ivec2(1, 0)).r;
    float d2 = textureLodOffset(inputDepth, uv, float(mipLevel), ivec2(0, 1)).r;
    float d3 = textureLodOffset(inputDepth, uv, float(mipLevel), ivec2(1, 1)).r;

    // Take maximum depth (conservative — ensures occluded objects are detected)
    float maxDepth = max(max(d0, d1), max(d2, d3));

    imageStore(outputDepth, ivec2(pos), vec4(maxDepth));
}

#version 450

// ============================================================
// Pictor Hologram Fragment Shader
//
// Stylised "holographic projection" look for SkillBox / Equipment
// cubes. Combines three effects:
//
//   1. Fresnel edge glow — view-angle dependent rim brightening,
//      `pow(1 - dot(N, V), kFresnelPower)`. Gives the silhouette a
//      bright outline.
//
//   2. Scan-line mask — sin() of world-space Y (frequency ~30 cycles
//      per unit), modulated over time so lines drift downward. Carves
//      thin dim bands across the surface.
//
//   3. Soft alpha — base alpha is multiplied by `(0.45 + 0.55*fresnel)`
//      so the interior is semi-transparent and the edge stays opaque,
//      reading correctly when blended on top of the scene.
//
// Pairs with shaders/hologram.vert (same SceneUBO / InstanceData
// layout as lit.{vert,frag}).
//
// Tuning constants are in the `// ── tunable ──` block below.
// ============================================================

layout(location = 0) in vec3 fragWorldPos;
layout(location = 1) in vec3 fragNormal;
layout(location = 2) in flat uint fragInstanceID;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 view;
    mat4 proj;
    vec4 lightDir;
    vec4 lightColor;
    vec4 cameraPos;
};

struct InstanceData {
    mat4  model;
    vec4  baseColor;
    uvec4 skinInfo;
};
layout(std430, set = 0, binding = 1) readonly buffer InstanceBuffer {
    InstanceData instances[];
};

// Optional scan-line scrolling: tied to `lightDir.w` doubling as a
// time channel when no dedicated push constant is bound. When the
// caller doesn't update `lightDir.w` (pure static scene) the bands
// just sit still — the effect is still visible.
layout(push_constant) uniform Push {
    float u_time;
} push;

layout(location = 0) out vec4 outColor;

// ── tunable ──
const float kFresnelPower    = 2.5;   // higher = thinner rim
const float kScanFrequency   = 28.0;  // bands per world-space unit
const float kScanScrollSpeed = 0.6;   // bands per second
const float kScanDarken      = 0.40;  // 0 = no bands, 1 = full black bands
const vec3  kEdgeTint        = vec3(1.05, 1.20, 1.40);  // cool rim light

void main() {
    InstanceData inst = instances[fragInstanceID];

    vec3 N = normalize(fragNormal);
    vec3 V = normalize(cameraPos.xyz - fragWorldPos);

    // 1) Fresnel — bright at glancing angles.
    float fresnel = pow(1.0 - clamp(dot(N, V), 0.0, 1.0), kFresnelPower);

    // 2) Scan-line mask. Use world-space Y so the bands stay stable
    //    in 3D as the camera moves; scroll downward over time.
    float scan = sin((fragWorldPos.y - push.u_time * kScanScrollSpeed)
                     * kScanFrequency * 6.2831853);
    // map sin()∈[-1,1] → mask∈[1-kScanDarken, 1.0] with a soft falloff.
    float bandMask = 1.0 - kScanDarken * smoothstep(0.0, 1.0, max(0.0, -scan));

    // 3) Compose. Interior is the cube's base colour at reduced
    //    intensity; the rim is tinted bright with the edge colour.
    vec3 interior = inst.baseColor.rgb * 0.85;
    vec3 rim      = kEdgeTint * fresnel;
    vec3 rgb      = (interior + rim) * bandMask;

    // Soft alpha: edges read solidly, inside sees through.
    float alpha = inst.baseColor.a * (0.40 + 0.60 * fresnel);

    outColor = vec4(rgb, alpha);
}

#version 450

// ============================================================
// Pictor Hologram Vertex Shader
//
// Minimal pass-through that forwards world position + normal to the
// fragment stage. Shares the SceneUBO + InstanceBuffer layout with
// lit.{vert,frag} so a hologram-styled draw can swap shaders without
// changing descriptors. No skinning — hologram targets static SkillBox
// / Equipment cubes.
//
// Vertex layout (24 bytes):
//   location 0: vec3 position
//   location 1: vec3 normal
// ============================================================

layout(location = 0) in vec3 inPosition;
layout(location = 1) in vec3 inNormal;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 view;
    mat4 proj;
    vec4 lightDir;
    vec4 lightColor;
    vec4 cameraPos;
};

struct InstanceData {
    mat4  model;
    vec4  baseColor;
    uvec4 skinInfo;
};
layout(std430, set = 0, binding = 1) readonly buffer InstanceBuffer {
    InstanceData instances[];
};

layout(location = 0) out vec3 fragWorldPos;
layout(location = 1) out vec3 fragNormal;
layout(location = 2) out flat uint fragInstanceID;

void main() {
    InstanceData inst = instances[gl_InstanceIndex];
    vec4 worldPos = inst.model * vec4(inPosition, 1.0);
    fragWorldPos   = worldPos.xyz;
    fragNormal     = normalize(mat3(inst.model) * inNormal);
    fragInstanceID = uint(gl_InstanceIndex);
    gl_Position    = proj * view * worldPos;
}

// Pictor — Static Lightmap Bake Shader
// Computes direct + indirect illumination for static objects.
// Multi-bounce: run once for direct, then iteratively for indirect bounces.
// Results are accumulated per-object as RGB direct + RGB indirect.

#version 450

layout(local_size_x = 256) in;

layout(set = 0, binding = 0) uniform LightmapBakeParams {
    vec4  lightDirection;       // xyz = direction (toward light), w = intensity
    vec4  lightColor;           // rgb = color, w = unused
    uint  objectCount;
    uint  totalSceneObjects;
    uint  pointLightCount;
    uint  bounceIndex;          // 0 = direct, 1+ = indirect bounce
    float indirectIntensity;    // multiplier for indirect contribution
    float padding0;
    float padding1;
    float padding2;
};

// Input: world-space AABB bounds
layout(std430, set = 0, binding = 1) readonly buffer Bounds {
    vec4 bake_bounds[];
};

// Input: world-space transforms
layout(std430, set = 0, binding = 2) readonly buffer Transforms {
    mat4 bake_transforms[];
};

// Input: point lights (position.xyz, radius, color.rgb, intensity)
layout(std430, set = 0, binding = 3) readonly buffer PointLights {
    vec4 point_lights[];  // pairs: [pos_radius, color_intensity]
};

// Input/Output: previous bounce lighting (read for indirect bounces)
layout(std430, set = 0, binding = 4) readonly buffer PrevBounce {
    vec4 prev_lighting[];  // rgb = previous bounce illumination, w = unused
};

// Output: current bounce lighting
// For bounce 0: direct lighting
// For bounce N: N-th indirect bounce contribution
layout(std430, set = 0, binding = 5) writeonly buffer CurrentBounce {
    vec4 current_lighting[];
};

// Simplified visibility test: does a ray from src to dst hit any AABB?
bool isOccluded(vec3 src, vec3 dst) {
    vec3 dir = dst - src;
    float maxDist = length(dir);
    if (maxDist < 1e-6) return false;
    dir /= maxDist;
    vec3 invDir = 1.0 / (dir + vec3(1e-8));

    for (uint j = 0; j < totalSceneObjects; j++) {
        vec3 aabbMin = bake_bounds[j * 2].xyz;
        vec3 aabbMax = bake_bounds[j * 2 + 1].xyz;

        // Skip if src or dst is inside this AABB
        vec3 center = (aabbMin + aabbMax) * 0.5;
        if (distance(center, src) < 0.1 || distance(center, dst) < 0.1) continue;

        vec3 t1 = (aabbMin - src) * invDir;
        vec3 t2 = (aabbMax - src) * invDir;
        vec3 tMin = min(t1, t2);
        vec3 tMax = max(t1, t2);
        float tNear = max(max(tMin.x, tMin.y), tMin.z);
        float tFar  = min(min(tMax.x, tMax.y), tMax.z);

        if (tFar >= max(tNear, 0.0) && tNear > 0.01 && tNear < maxDist - 0.01) {
            return true;
        }
    }
    return false;
}

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    vec3 aabbMin = bake_bounds[idx * 2].xyz;
    vec3 aabbMax = bake_bounds[idx * 2 + 1].xyz;
    vec3 center  = (aabbMin + aabbMax) * 0.5;

    // Estimate a surface normal (simplified: use upward normal)
    // In a real implementation, per-vertex normals would be used
    vec3 normal = vec3(0.0, 1.0, 0.0);

    vec3 lighting = vec3(0.0);

    if (bounceIndex == 0) {
        // ---- Direct lighting ----

        // Directional light
        vec3 L = -lightDirection.xyz;
        float NdotL = max(dot(normal, L), 0.0);

        if (NdotL > 0.0) {
            // Shadow test: cast ray toward light
            vec3 lightPos = center + L * 1000.0; // distant directional light
            if (!isOccluded(center, lightPos)) {
                lighting += lightColor.rgb * lightDirection.w * NdotL;
            }
        }

        // Point lights
        for (uint p = 0; p < pointLightCount; p++) {
            vec3 plPos     = point_lights[p * 2].xyz;
            float plRadius = point_lights[p * 2].w;
            vec3 plColor   = point_lights[p * 2 + 1].xyz;
            float plIntens = point_lights[p * 2 + 1].w;

            vec3 toLight = plPos - center;
            float dist = length(toLight);
            if (dist > plRadius || dist < 1e-4) continue;

            vec3 plDir = toLight / dist;
            float plNdotL = max(dot(normal, plDir), 0.0);
            if (plNdotL <= 0.0) continue;

            // Attenuation (inverse square with radius falloff)
            float atten = 1.0 / (dist * dist + 1.0);
            atten *= 1.0 - smoothstep(plRadius * 0.8, plRadius, dist);

            if (!isOccluded(center, plPos)) {
                lighting += plColor * plIntens * plNdotL * atten;
            }
        }

    } else {
        // ---- Indirect bounce ----
        // Gather light from nearby objects that received light in the previous bounce.
        // Each neighbor acts as a virtual area light, redistributing its received energy.

        for (uint j = 0; j < objectCount; j++) {
            if (j == idx) continue;

            vec3 neighborMin = bake_bounds[j * 2].xyz;
            vec3 neighborMax = bake_bounds[j * 2 + 1].xyz;
            vec3 neighborCenter = (neighborMin + neighborMax) * 0.5;

            vec3 toNeighbor = neighborCenter - center;
            float dist = length(toNeighbor);
            if (dist < 1e-4 || dist > 20.0) continue; // max indirect range

            vec3 dir = toNeighbor / dist;
            float NdotL = max(dot(normal, dir), 0.0);
            if (NdotL <= 0.0) continue;

            // Previous bounce energy of the neighbor
            vec3 neighborEnergy = prev_lighting[j].rgb;
            if (dot(neighborEnergy, neighborEnergy) < 1e-8) continue;

            // Approximate form factor
            float sa = (neighborMax.x - neighborMin.x) *
                       (neighborMax.y - neighborMin.y);
            float formFactor = sa * NdotL / (dist * dist + 1.0);
            formFactor = min(formFactor, 1.0);

            if (!isOccluded(center, neighborCenter)) {
                lighting += neighborEnergy * formFactor * indirectIntensity;
            }
        }
    }

    current_lighting[idx] = vec4(lighting, 1.0);
}

#version 450

// ============================================================
// Pictor General-Purpose Lit Fragment Shader
//
// Simple Lambert diffuse + ambient + optional half-Lambert wrap
// for pleasant appearance without HDR/tonemapping setup.
// Pairs with shaders/lit.vert.
// ============================================================

layout(location = 0) in vec3 fragWorldPos;
layout(location = 1) in vec3 fragNormal;
layout(location = 2) in flat uint fragInstanceID;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 view;
    mat4 proj;
    vec4 lightDir;     // xyz = direction TOWARD light, w = intensity
    vec4 lightColor;   // rgb = light color, a = ambient intensity
    vec4 cameraPos;
};

struct InstanceData {
    mat4 model;
    vec4 baseColor;
    uvec4 skinInfo;
};
layout(std430, set = 0, binding = 1) readonly buffer InstanceBuffer {
    InstanceData instances[];
};

layout(location = 0) out vec4 outColor;

void main() {
    InstanceData inst = instances[fragInstanceID];

    vec3 N = normalize(fragNormal);
    vec3 L = normalize(lightDir.xyz);

    // Half-Lambert: keeps shadowed side from going pitch black.
    float NdotL = dot(N, L);
    float halfLambert = NdotL * 0.5 + 0.5;
    float wrap = mix(max(NdotL, 0.0), halfLambert, 0.25);

    vec3 albedo = inst.baseColor.rgb;
    vec3 ambient = albedo * lightColor.a;
    vec3 diffuse = albedo * lightColor.rgb * wrap * lightDir.w;

    outColor = vec4(ambient + diffuse, inst.baseColor.a);
}

#version 450

// ============================================================
// Pictor General-Purpose Lit Vertex Shader (with skinning)
//
// Vertex layout (56 bytes):
//   location 0: vec3  position
//   location 1: vec3  normal
//   location 2: uvec4 joint_indices   (up to 4 bone influences)
//   location 3: vec4  joint_weights   (sum should be 1.0)
//
// For non-skinned meshes, set joint_indices = (0,0,0,0) and
// joint_weights = (1,0,0,0), and upload an identity bone matrix
// at bone_matrices[0].
//
// Set 0:
//   binding 0 (UBO):  SceneUBO  — view, proj, light, camera
//   binding 1 (SSBO): instances[] — per-instance model matrix + color
//   binding 2 (SSBO): bone_matrices[] — skinning transforms
// ============================================================

layout(location = 0) in vec3  inPosition;
layout(location = 1) in vec3  inNormal;
layout(location = 2) in uvec4 inJoints;
layout(location = 3) in vec4  inWeights;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 view;
    mat4 proj;
    vec4 lightDir;     // xyz = world-space direction toward light, w = intensity
    vec4 lightColor;   // rgb, a = ambient intensity
    vec4 cameraPos;    // xyz = world-space camera position
};

struct InstanceData {
    mat4 model;
    vec4 baseColor;    // rgb = Lambert diffuse albedo, a = opacity
    // xy = (bone_offset, bone_count) so the same SSBO can be shared across
    // multiple skinned instances. z, w reserved.
    uvec4 skinInfo;
};
layout(std430, set = 0, binding = 1) readonly buffer InstanceBuffer {
    InstanceData instances[];
};

layout(std430, set = 0, binding = 2) readonly buffer BoneMatricesBuffer {
    mat4 bone_matrices[];
};

layout(location = 0) out vec3 fragWorldPos;
layout(location = 1) out vec3 fragNormal;
layout(location = 2) out flat uint fragInstanceID;

void main() {
    InstanceData inst = instances[gl_InstanceIndex];

    // ── Skinning (linear blend) ──────────────────────────
    uint boneOffset = inst.skinInfo.x;
    float wSum = inWeights.x + inWeights.y + inWeights.z + inWeights.w;

    mat4 skinMat;
    if (wSum > 0.0001) {
        skinMat  = bone_matrices[boneOffset + inJoints.x] * inWeights.x;
        skinMat += bone_matrices[boneOffset + inJoints.y] * inWeights.y;
        skinMat += bone_matrices[boneOffset + inJoints.z] * inWeights.z;
        skinMat += bone_matrices[boneOffset + inJoints.w] * inWeights.w;
    } else {
        // Fall back to identity so unskinned meshes still render.
        skinMat = mat4(1.0);
    }

    vec4 skinnedPos    = skinMat * vec4(inPosition, 1.0);
    vec3 skinnedNormal = mat3(skinMat) * inNormal;

    // ── Model / view / projection ────────────────────────
    vec4 worldPos = inst.model * skinnedPos;
    mat3 normalMat = mat3(inst.model);
    fragWorldPos   = worldPos.xyz;
    fragNormal     = normalize(normalMat * skinnedNormal);
    fragInstanceID = uint(gl_InstanceIndex);
    gl_Position    = proj * view * worldPos;
}

// Pictor — LOD Selection Shader (§7.2 Step 3)
// Selects appropriate LOD level based on camera distance.

#version 450

layout(local_size_x = 256) in;

layout(set = 0, binding = 0) uniform LODParams {
    vec4  cameraPos;
    uint  objectCount;
    uint  maxLODLevels;
    float lodDistances[8]; // Distance thresholds for LOD levels
};

// Transform positions for distance calculation
layout(std430, set = 0, binding = 1) readonly buffer Transforms {
    mat4 gpu_transforms[];
};

// LOD info per object
layout(std430, set = 0, binding = 2) readonly buffer LODInfo {
    // x = numLODs, y = meshId_LOD0, z = meshId_LOD1, w = meshId_LOD2
    uvec4 gpu_lod_info[];
};

// Output: visibility + selected LOD (packed)
layout(std430, set = 0, binding = 3) buffer Visibility {
    uint gpu_visibility[]; // bits 0-7: visible, bits 8-15: LOD level
};

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    // Skip if already culled
    if ((gpu_visibility[idx] & 0xFF) == 0) return;

    // Get object position from transform matrix
    vec3 objPos = gpu_transforms[idx][3].xyz;
    float dist = distance(objPos, cameraPos.xyz);

    // Select LOD based on distance (§7.2)
    uint lodLevel = 0;
    uint numLODs = gpu_lod_info[idx].x;

    for (uint i = 0; i < min(numLODs, maxLODLevels); i++) {
        if (dist > lodDistances[i]) {
            lodLevel = i + 1;
        }
    }

    lodLevel = min(lodLevel, numLODs - 1);

    // Pack LOD level into visibility flags
    gpu_visibility[idx] = (gpu_visibility[idx] & 0xFF) | (lodLevel << 8);
}

// Pictor — PBR Fragment Shader
// Cook-Torrance BRDF with metallic-roughness workflow.
// Supports: albedo, normal, metallic-roughness, AO, emissive maps.
// Supports: CSM shadow mapping with PCF/PCSS soft shadows.

#version 450
#extension GL_GOOGLE_include_directive : require

#include "common.glsl"
#include "shadow.glsl"

// ============================================================
// Fragment Input
// ============================================================

layout(location = 0) in vec3 fragWorldPos;
layout(location = 1) in vec2 fragTexCoord;
layout(location = 2) in vec3 fragNormal;
layout(location = 3) in vec3 fragTangent;
layout(location = 4) in vec3 fragBitangent;

// ============================================================
// Material Textures (set = 1)
// ============================================================

layout(set = 1, binding = 0) uniform sampler2D albedoMap;
layout(set = 1, binding = 1) uniform sampler2D normalMap;
layout(set = 1, binding = 2) uniform sampler2D metallicRoughnessMap; // G = roughness, B = metallic
layout(set = 1, binding = 3) uniform sampler2D aoMap;
layout(set = 1, binding = 4) uniform sampler2D emissiveMap;

// ============================================================
// Material Parameters (set = 1, binding = 5)
// ============================================================

layout(set = 1, binding = 5) uniform MaterialParams {
    vec4  baseColorFactor;     // linear-space RGBA multiplier
    float metallicFactor;
    float roughnessFactor;
    float aoStrength;
    float emissiveStrength;
    vec4  emissiveFactor;      // RGB emissive multiplier
    uint  receiveShadow;       // 1 = sample shadow map, 0 = skip
    uint  matPad0, matPad1, matPad2;
};

// ============================================================
// Output
// ============================================================

layout(location = 0) out vec4 outColor;

// ============================================================
// GGX / Cook-Torrance BRDF
// ============================================================

// GGX Normal Distribution Function
float distributionGGX(vec3 N, vec3 H, float roughness) {
    float a  = roughness * roughness;
    float a2 = a * a;
    float NdotH  = max(dot(N, H), 0.0);
    float NdotH2 = NdotH * NdotH;

    float denom = NdotH2 * (a2 - 1.0) + 1.0;
    return a2 / (PI * denom * denom + EPSILON);
}

// Smith's geometry function (Schlick-GGX)
float geometrySchlickGGX(float NdotV, float roughness) {
    float r = roughness + 1.0;
    float k = (r * r) / 8.0;
    return NdotV / (NdotV * (1.0 - k) + k + EPSILON);
}

// Smith's method for combined geometry obstruction
float geometrySmith(vec3 N, vec3 V, vec3 L, float roughness) {
    float NdotV = max(dot(N, V), 0.0);
    float NdotL = max(dot(N, L), 0.0);
    return geometrySchlickGGX(NdotV, roughness) *
           geometrySchlickGGX(NdotL, roughness);
}

// ============================================================
// Lighting Calculation
// ============================================================

vec3 evaluateBRDF(vec3 N, vec3 V, vec3 L, vec3 radiance,
                  vec3 albedo, float metallic, float roughness) {
    vec3 H = normalize(V + L);

    // Dielectric F0 = 0.04, metallic F0 = albedo
    vec3 F0 = mix(vec3(0.04), albedo, metallic);

    // Cook-Torrance specular
    float D = distributionGGX(N, H, roughness);
    float G = geometrySmith(N, V, L, roughness);
    vec3  F = fresnelSchlick(max(dot(H, V), 0.0), F0);

    float NdotL = max(dot(N, L), 0.0);
    float NdotV = max(dot(N, V), 0.0);

    vec3 numerator  = D * G * F;
    float denominator = 4.0 * NdotV * NdotL + EPSILON;
    vec3 specular = numerator / denominator;

    // Energy conservation: diffuse is reduced by specular reflection
    vec3 kD = (vec3(1.0) - F) * (1.0 - metallic);

    // Lambertian diffuse
    vec3 diffuse = kD * albedo * INV_PI;

    return (diffuse + specular) * radiance * NdotL;
}

void main() {
    // Sample material textures
    vec4 albedoSample = texture(albedoMap, fragTexCoord);
    vec3 albedo       = srgbToLinear(albedoSample.rgb) * baseColorFactor.rgb;
    float alpha       = albedoSample.a * baseColorFactor.a;

    vec2 mr       = texture(metallicRoughnessMap, fragTexCoord).gb;
    float metallic  = mr.y * metallicFactor;
    float roughness = mr.x * roughnessFactor;
    roughness = clamp(roughness, 0.04, 1.0);

    float ao       = mix(1.0, texture(aoMap, fragTexCoord).r, aoStrength);
    vec3 emissive  = srgbToLinear(texture(emissiveMap, fragTexCoord).rgb)
                     * emissiveFactor.rgb * emissiveStrength;

    // Reconstruct TBN normal
    vec3 N = fragNormal;
    vec3 T = fragTangent;
    vec3 B = fragBitangent;
    vec3 mapN = texture(normalMap, fragTexCoord).rgb * 2.0 - 1.0;
    N = perturbNormal(normalize(N), normalize(T), normalize(B), mapN);

    vec3 V = normalize(cameraPosition.xyz - fragWorldPos);

    // ---- Compute view-space depth for cascade selection ----
    vec4 viewPos = view * vec4(fragWorldPos, 1.0);
    float viewDepth = -viewPos.z; // positive depth toward camera

    // ---- Compute shadow factor ----
    float shadow = 1.0;
    if (receiveShadow != 0u) {
        vec3 sunDir = normalize(sun.direction.xyz);
        shadow = sampleShadow(fragWorldPos, viewDepth, N, sunDir);
    }

    // ---- Accumulate lighting ----
    vec3 Lo = vec3(0.0);

    // Directional light (sun) — modulated by shadow
    {
        vec3 L = normalize(sun.direction.xyz);
        vec3 radiance = sun.color.rgb * sun.color.a;
        Lo += evaluateBRDF(N, V, L, radiance, albedo, metallic, roughness) * shadow;
    }

    // Point lights (no shadow mapping for point lights currently)
    for (uint i = 0; i < activePointLights; i++) {
        vec3 lightVec = pointLights[i].position.xyz - fragWorldPos;
        float dist    = length(lightVec);
        vec3 L        = lightVec / dist;

        float atten   = attenuatePoint(dist, pointLights[i].position.w);
        vec3 radiance = pointLights[i].color.rgb * pointLights[i].color.a * atten;

        Lo += evaluateBRDF(N, V, L, radiance, albedo, metallic, roughness);
    }

    // Ambient (simplified IBL substitute) — not affected by directional shadow
    vec3 F0 = mix(vec3(0.04), albedo, metallic);
    vec3 kS = fresnelSchlickRoughness(max(dot(N, V), 0.0), F0, roughness);
    vec3 kD = (1.0 - kS) * (1.0 - metallic);
    vec3 ambient = (kD * albedo + kS * 0.03) * ambientColor.rgb * ambientColor.a * ao;

    vec3 color = ambient + Lo + emissive;

    // Tone mapping and gamma correction
    color = toneMapACES(color);
    color = linearToSrgb(color);

    outColor = vec4(color, alpha);
}

// Pictor — PBR Vertex Shader
// Standard vertex transform with TBN output for normal mapping.

#version 450
#extension GL_GOOGLE_include_directive : require

#include "common.glsl"

// ============================================================
// Vertex Input (location matches Pictor vertex layout)
// ============================================================

layout(location = 0) in vec3 inPosition;
layout(location = 1) in vec3 inNormal;
layout(location = 2) in vec4 inTangent;    // xyz = tangent, w = handedness (+1/-1)
layout(location = 3) in vec2 inTexCoord0;

// ============================================================
// Vertex Output
// ============================================================

layout(location = 0) out vec3 fragWorldPos;
layout(location = 1) out vec2 fragTexCoord;
layout(location = 2) out vec3 fragNormal;
layout(location = 3) out vec3 fragTangent;
layout(location = 4) out vec3 fragBitangent;

void main() {
    vec4 worldPos = model * vec4(inPosition, 1.0);
    fragWorldPos  = worldPos.xyz;
    fragTexCoord  = inTexCoord0;

    // Transform normal and tangent to world space
    mat3 nMat    = mat3(normalMatrix);
    fragNormal   = normalize(nMat * inNormal);
    fragTangent  = normalize(nMat * inTangent.xyz);
    fragBitangent = cross(fragNormal, fragTangent) * inTangent.w;

    gl_Position = viewProjection * worldPos;
}

// Pictor — Bloom Separable Gaussian Blur
// One axis per invocation (horizontal then vertical). 9-tap Gaussian.

#version 450

layout(location = 0) in  vec2 inUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D srcTex;

layout(push_constant) uniform Params {
    vec2  direction;  // texel step on the blur axis (1/w,0) or (0,1/h)
    float radius;     // blur radius multiplier
    float _pad0;
};

void main() {
    // Normalized 9-tap Gaussian weights (sigma ~ 2).
    const float w0 = 0.227027;
    const float w1 = 0.194594;
    const float w2 = 0.121622;
    const float w3 = 0.054054;
    const float w4 = 0.016216;

    vec2 step = direction * radius;
    vec3 acc = texture(srcTex, inUV).rgb * w0;
    acc += texture(srcTex, inUV + step * 1.0).rgb * w1;
    acc += texture(srcTex, inUV - step * 1.0).rgb * w1;
    acc += texture(srcTex, inUV + step * 2.0).rgb * w2;
    acc += texture(srcTex, inUV - step * 2.0).rgb * w2;
    acc += texture(srcTex, inUV + step * 3.0).rgb * w3;
    acc += texture(srcTex, inUV - step * 3.0).rgb * w3;
    acc += texture(srcTex, inUV + step * 4.0).rgb * w4;
    acc += texture(srcTex, inUV - step * 4.0).rgb * w4;

    outColor = vec4(acc, 1.0);
}

// Pictor — Bloom Composite Fragment Shader
// Additively blends bloom result with the original HDR scene color.

#version 450

layout(location = 0) in vec2 inUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D sceneColor;
layout(set = 0, binding = 1) uniform sampler2D bloomTexture;

layout(push_constant) uniform BloomCompositeParams {
    float intensity;
};

void main() {
    vec3 scene = texture(sceneColor, inUV).rgb;
    vec3 bloom = texture(bloomTexture, inUV).rgb;

    outColor = vec4(scene + bloom * intensity, 1.0);
}

// Pictor — Bloom Progressive Downsample (Compute Shader)
// 13-tap filter for high-quality downsampling through the bloom mip chain.
// Based on the technique from Call of Duty: Advanced Warfare (Jimenez, 2014).

#version 450

layout(local_size_x = 8, local_size_y = 8, local_size_z = 1) in;

layout(set = 0, binding = 0) uniform sampler2D inputTexture;
layout(set = 0, binding = 1, rgba16f) uniform writeonly image2D outputImage;

layout(push_constant) uniform DownsampleParams {
    vec2 inputTexelSize;  // 1.0 / input resolution
};

void main() {
    ivec2 pixel = ivec2(gl_GlobalInvocationID.xy);
    ivec2 outputSize = imageSize(outputImage);
    if (pixel.x >= outputSize.x || pixel.y >= outputSize.y) return;

    vec2 uv = (vec2(pixel) + 0.5) / vec2(outputSize);

    // 13-tap downsampling filter
    // Sample pattern (. = texel center, X = sample position):
    //
    //   A . B . C
    //   . D . E .
    //   F . G . H
    //   . I . J .
    //   K . L . M
    //
    // Weights are designed to match a 4x4 box filter with bilinear sampling

    vec2 ts = inputTexelSize;

    vec3 A = textureLod(inputTexture, uv + vec2(-2, -2) * ts, 0.0).rgb;
    vec3 B = textureLod(inputTexture, uv + vec2( 0, -2) * ts, 0.0).rgb;
    vec3 C = textureLod(inputTexture, uv + vec2( 2, -2) * ts, 0.0).rgb;

    vec3 D = textureLod(inputTexture, uv + vec2(-1, -1) * ts, 0.0).rgb;
    vec3 E = textureLod(inputTexture, uv + vec2( 1, -1) * ts, 0.0).rgb;

    vec3 F = textureLod(inputTexture, uv + vec2(-2,  0) * ts, 0.0).rgb;
    vec3 G = textureLod(inputTexture, uv,                      0.0).rgb;
    vec3 H = textureLod(inputTexture, uv + vec2( 2,  0) * ts, 0.0).rgb;

    vec3 I = textureLod(inputTexture, uv + vec2(-1,  1) * ts, 0.0).rgb;
    vec3 J = textureLod(inputTexture, uv + vec2( 1,  1) * ts, 0.0).rgb;

    vec3 K = textureLod(inputTexture, uv + vec2(-2,  2) * ts, 0.0).rgb;
    vec3 L = textureLod(inputTexture, uv + vec2( 0,  2) * ts, 0.0).rgb;
    vec3 M = textureLod(inputTexture, uv + vec2( 2,  2) * ts, 0.0).rgb;

    // Weighted average (total = 1.0)
    // Center cross: (D+E+I+J) * 0.125 * 2 = 0.5
    // Corners:      (A+B+F+G) * 0.03125 etc.
    vec3 result = vec3(0.0);
    result += (D + E + I + J) * 0.125;     // 4 inner samples × 0.125 = 0.5
    result += (A + C + K + M) * 0.03125;   // 4 corners × 0.03125 = 0.125
    result += (B + F + H + L) * 0.0625;    // 4 edges × 0.0625 = 0.25
    result += G * 0.125;                    // center × 0.125

    imageStore(outputImage, pixel, vec4(result, 1.0));
}

// Pictor — Bloom Brightness Extraction (Compute Shader)
// Extracts pixels above a luminance threshold with soft knee transition.
// Output is written to half-resolution texture (first bloom mip).

#version 450

layout(local_size_x = 8, local_size_y = 8, local_size_z = 1) in;

layout(set = 0, binding = 0) uniform sampler2D inputTexture;
layout(set = 0, binding = 1, rgba16f) uniform writeonly image2D outputImage;

layout(push_constant) uniform BloomExtractParams {
    float threshold;
    float softThreshold;
    vec2  inputTexelSize;   // 1.0 / inputResolution
};

void main() {
    ivec2 pixel = ivec2(gl_GlobalInvocationID.xy);
    ivec2 outputSize = imageSize(outputImage);
    if (pixel.x >= outputSize.x || pixel.y >= outputSize.y) return;

    // Sample from full-res input at the center of 2x2 block (downsample)
    vec2 uv = (vec2(pixel) + 0.5) * 2.0 * inputTexelSize;

    // 4-tap box filter for initial downsample (average 2x2 block)
    vec3 color = vec3(0.0);
    color += textureLod(inputTexture, uv + vec2(-0.5, -0.5) * inputTexelSize, 0.0).rgb;
    color += textureLod(inputTexture, uv + vec2( 0.5, -0.5) * inputTexelSize, 0.0).rgb;
    color += textureLod(inputTexture, uv + vec2(-0.5,  0.5) * inputTexelSize, 0.0).rgb;
    color += textureLod(inputTexture, uv + vec2( 0.5,  0.5) * inputTexelSize, 0.0).rgb;
    color *= 0.25;

    // Compute luminance
    float luminance = dot(color, vec3(0.2126, 0.7152, 0.0722));

    // Soft threshold knee curve
    float knee = threshold * softThreshold;
    float soft = luminance - threshold + knee;
    soft = clamp(soft / (2.0 * knee + 0.00001), 0.0, 1.0);
    soft = soft * soft;

    // Contribution factor
    float contribution = max(soft, step(threshold, luminance));

    imageStore(outputImage, pixel, vec4(color * contribution, 1.0));
}

// Pictor — Bloom Bright-Pass Extraction
// Extracts pixels above a brightness threshold with a soft knee, so only
// bright HDR areas contribute to bloom.

#version 450

layout(location = 0) in  vec2 inUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D sceneColor;

layout(push_constant) uniform Params {
    float threshold;       // brightness cutoff
    float soft_threshold;  // soft knee width (0..1 of threshold)
    float _pad0;
    float _pad1;
};

void main() {
    vec3 c = texture(sceneColor, inUV).rgb;
    float brightness = max(c.r, max(c.g, c.b));

    // Soft knee: smooth transition around the threshold (UE4-style curve).
    float knee  = threshold * soft_threshold + 1e-5;
    float soft  = clamp(brightness - threshold + knee, 0.0, 2.0 * knee);
    soft        = soft * soft / (4.0 * knee + 1e-5);
    float weight = max(soft, brightness - threshold) / max(brightness, 1e-5);

    outColor = vec4(c * weight, 1.0);
}

// Pictor — Bloom Progressive Upsample (Compute Shader)
// 9-tap tent filter for smooth upsampling with mip-level scatter blending.
// Accumulates bloom contribution from smaller mip levels upward.

#version 450

layout(local_size_x = 8, local_size_y = 8, local_size_z = 1) in;

layout(set = 0, binding = 0) uniform sampler2D inputTexture;   // smaller mip (to upsample)
layout(set = 0, binding = 1) uniform sampler2D currentMip;     // current mip (to blend with)
layout(set = 0, binding = 2, rgba16f) uniform writeonly image2D outputImage;

layout(push_constant) uniform UpsampleParams {
    vec2  inputTexelSize;  // 1.0 / input (smaller mip) resolution
    float scatter;         // blend weight for upsampled contribution
};

void main() {
    ivec2 pixel = ivec2(gl_GlobalInvocationID.xy);
    ivec2 outputSize = imageSize(outputImage);
    if (pixel.x >= outputSize.x || pixel.y >= outputSize.y) return;

    vec2 uv = (vec2(pixel) + 0.5) / vec2(outputSize);
    vec2 ts = inputTexelSize;

    // 9-tap tent filter (3x3 bilinear, normalized):
    //   1 2 1
    //   2 4 2
    //   1 2 1  (÷ 16)
    vec3 upsampled = vec3(0.0);
    upsampled += textureLod(inputTexture, uv + vec2(-1, -1) * ts, 0.0).rgb * 1.0;
    upsampled += textureLod(inputTexture, uv + vec2( 0, -1) * ts, 0.0).rgb * 2.0;
    upsampled += textureLod(inputTexture, uv + vec2( 1, -1) * ts, 0.0).rgb * 1.0;
    upsampled += textureLod(inputTexture, uv + vec2(-1,  0) * ts, 0.0).rgb * 2.0;
    upsampled += textureLod(inputTexture, uv,                      0.0).rgb * 4.0;
    upsampled += textureLod(inputTexture, uv + vec2( 1,  0) * ts, 0.0).rgb * 2.0;
    upsampled += textureLod(inputTexture, uv + vec2(-1,  1) * ts, 0.0).rgb * 1.0;
    upsampled += textureLod(inputTexture, uv + vec2( 0,  1) * ts, 0.0).rgb * 2.0;
    upsampled += textureLod(inputTexture, uv + vec2( 1,  1) * ts, 0.0).rgb * 1.0;
    upsampled /= 16.0;

    // Blend with current mip level using scatter weight
    vec3 existing = textureLod(currentMip, uv, 0.0).rgb;
    vec3 result = mix(existing, upsampled, scatter);

    imageStore(outputImage, pixel, vec4(result, 1.0));
}

// Pictor — Post-Process Final Composite
// One fullscreen pass that performs, in order:
//   1. additive bloom composite (HDR)
//   2. exposure + tone mapping (HDR -> LDR)
//   3. saturation
//   4. LUT color grading (neutral LUT strip)
//   5. vignette
//   6. gamma correction
//
// set 0 binding 0: scene HDR color
// set 0 binding 1: blurred bloom texture
// set 0 binding 2: LUT strip (RGBA8, lut_size tall x lut_size*lut_size wide)

#version 450

layout(location = 0) in  vec2 inUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D sceneColor;
layout(set = 0, binding = 1) uniform sampler2D bloomTex;
layout(set = 0, binding = 2) uniform sampler2D lutTex;

layout(push_constant) uniform Params {
    float bloom_intensity;
    uint  tonemap_op;          // 0=ACES 1=Reinhard 2=ReinhardExt 3=Uncharted2 4=Linear
    float exposure;
    float gamma;
    float white_point;
    float saturation;
    float vignette_intensity;
    float vignette_radius;
    float vignette_softness;
    float lut_intensity;
    float lut_size;
    float vig_r;
    float vig_g;
    float vig_b;
};

// ---- Tone mapping operators ----
vec3 toneMapACES(vec3 c) {
    const float a = 2.51, b = 0.03, cc = 2.43, d = 0.59, e = 0.14;
    return clamp((c * (a * c + b)) / (c * (cc * c + d) + e), 0.0, 1.0);
}
vec3 toneMapReinhard(vec3 c) {
    float lum = dot(c, vec3(0.2126, 0.7152, 0.0722));
    return c * ((lum / (1.0 + lum)) / max(lum, 1e-4));
}
vec3 toneMapReinhardExt(vec3 c, float wp) {
    float lum = dot(c, vec3(0.2126, 0.7152, 0.0722));
    float numer = lum * (1.0 + lum / (wp * wp));
    return c * ((numer / (1.0 + lum)) / max(lum, 1e-4));
}
vec3 uncharted2Partial(vec3 x) {
    const float A = 0.15, B = 0.50, C = 0.10, D = 0.20, E = 0.02, F = 0.30;
    return ((x * (A * x + C * B) + D * E) / (x * (A * x + B) + D * F)) - E / F;
}
vec3 toneMapUncharted2(vec3 c) {
    vec3 curr = uncharted2Partial(c * 2.0);
    vec3 whiteScale = vec3(1.0) / uncharted2Partial(vec3(11.2));
    return curr * whiteScale;
}

// ---- LUT strip lookup (neutral LUT, size N) ----
vec3 applyLUT(vec3 color, float N) {
    color = clamp(color, 0.0, 1.0);
    float blue = color.b * (N - 1.0);
    float b0 = floor(blue);
    float b1 = min(b0 + 1.0, N - 1.0);
    float f  = blue - b0;

    float u_in = (0.5 + color.r * (N - 1.0)) / (N * N);
    float v    = (0.5 + color.g * (N - 1.0)) / N;

    vec3 s0 = texture(lutTex, vec2(b0 / N + u_in, v)).rgb;
    vec3 s1 = texture(lutTex, vec2(b1 / N + u_in, v)).rgb;
    return mix(s0, s1, f);
}

void main() {
    vec3 scene = texture(sceneColor, inUV).rgb;
    vec3 bloom = texture(bloomTex, inUV).rgb;

    // 1. additive bloom composite (HDR space)
    vec3 color = scene + bloom * bloom_intensity;

    // 2. exposure + tone mapping
    color *= exposure;
    switch (tonemap_op) {
        case 0u: color = toneMapACES(color);                       break;
        case 1u: color = toneMapReinhard(color);                   break;
        case 2u: color = toneMapReinhardExt(color, white_point);   break;
        case 3u: color = toneMapUncharted2(color);                 break;
        default: color = clamp(color, 0.0, 1.0);                   break;
    }

    // 3. saturation
    float gray = dot(color, vec3(0.2126, 0.7152, 0.0722));
    color = mix(vec3(gray), color, saturation);
    color = clamp(color, 0.0, 1.0);

    // 4. LUT color grading
    if (lut_intensity > 0.0) {
        vec3 graded = applyLUT(color, lut_size);
        color = mix(color, graded, lut_intensity);
    }

    // 5. vignette
    if (vignette_intensity > 0.0) {
        vec2 d = inUV - 0.5;
        float dist = length(d) * 1.41421356;  // 0 center .. ~1 corner
        float edge = smoothstep(vignette_radius,
                                vignette_radius + vignette_softness, dist);
        color = mix(color, vec3(vig_r, vig_g, vig_b), edge * vignette_intensity);
    }

    // 6. gamma correction (linear -> display)
    color = pow(max(color, 0.0), vec3(1.0 / gamma));

    outColor = vec4(color, 1.0);
}

// Pictor — Depth of Field (Compute Shader)
// Combined CoC computation + disc blur + composite.
// Supports separate near/far field blur with variable-radius bokeh.

#version 450

layout(local_size_x = 8, local_size_y = 8, local_size_z = 1) in;

layout(set = 0, binding = 0) uniform sampler2D colorTexture;
layout(set = 0, binding = 1) uniform sampler2D depthTexture;
layout(set = 0, binding = 2, rgba16f) uniform writeonly image2D outputImage;

layout(push_constant) uniform DoFParams {
    float focusDistance;
    float focusRange;
    float bokehRadius;
    float nearStart;
    float nearEnd;
    float farStart;
    float farEnd;
    uint  sampleCount;
    vec2  texelSize;
};

// Poisson disc samples (16 points, normalized to unit disc)
const vec2 poissonDisc[16] = vec2[](
    vec2(-0.94201,  -0.39906),
    vec2( 0.94558,  -0.76890),
    vec2(-0.09418,  -0.92938),
    vec2( 0.34495,   0.29387),
    vec2(-0.91588,   0.45771),
    vec2(-0.81544,  -0.87912),
    vec2( 0.19984,  -0.29614),
    vec2(-0.24188,   0.99706),
    vec2( 0.44323,   0.93427),
    vec2( 0.78583,   0.00399),
    vec2(-0.52389,  -0.22294),
    vec2( 0.36291,  -0.67380),
    vec2(-0.54532,   0.63536),
    vec2( 0.13980,   0.56616),
    vec2(-0.30654,  -0.60812),
    vec2( 0.74882,   0.56394)
);

float computeCoC(float depth) {
    // Near field (negative CoC)
    float nearCoC = smoothstep(nearEnd, nearStart, depth);
    // Far field (positive CoC)
    float farCoC = smoothstep(farStart, farEnd, depth);

    // Focus region
    float halfRange = focusRange * 0.5;
    if (depth >= focusDistance - halfRange && depth <= focusDistance + halfRange) {
        return 0.0;
    }

    return depth < focusDistance ? -nearCoC * bokehRadius : farCoC * bokehRadius;
}

void main() {
    ivec2 pixel = ivec2(gl_GlobalInvocationID.xy);
    ivec2 outputSize = imageSize(outputImage);
    if (pixel.x >= outputSize.x || pixel.y >= outputSize.y) return;

    vec2 uv = (vec2(pixel) + 0.5) / vec2(outputSize);

    float centerDepth = texture(depthTexture, uv).r;
    float coc = computeCoC(centerDepth);
    float absCoC = abs(coc);

    // If CoC is negligible, output sharp color
    if (absCoC < 0.5) {
        vec3 sharp = texture(colorTexture, uv).rgb;
        imageStore(outputImage, pixel, vec4(sharp, 1.0));
        return;
    }

    // Variable-radius disc blur
    vec3 colorSum = vec3(0.0);
    float weightSum = 0.0;
    uint samples = min(sampleCount, 16u);

    for (uint i = 0; i < samples; ++i) {
        vec2 offset = poissonDisc[i] * absCoC * texelSize;
        vec2 sampleUV = uv + offset;

        vec3 sampleColor = texture(colorTexture, sampleUV).rgb;
        float sampleDepth = texture(depthTexture, sampleUV).r;
        float sampleCoC = abs(computeCoC(sampleDepth));

        // Weight: accept sample if its CoC covers the center pixel
        float weight = smoothstep(0.0, 2.0, sampleCoC);
        colorSum += sampleColor * weight;
        weightSum += weight;
    }

    vec3 blurred = colorSum / max(weightSum, 0.001);

    // Blend between sharp and blurred based on CoC magnitude
    vec3 sharp = texture(colorTexture, uv).rgb;
    float blendFactor = smoothstep(0.5, 2.0, absCoC);
    vec3 result = mix(sharp, blurred, blendFactor);

    imageStore(outputImage, pixel, vec4(result, 1.0));
}

// Pictor — Fullscreen Triangle Vertex Shader
// Generates a fullscreen triangle without any vertex buffer.
// Invoke with 3 vertices (gl_VertexIndex = 0, 1, 2).
// Covers the viewport with a single triangle (more efficient than a quad).

#version 450

layout(location = 0) out vec2 outUV;

void main() {
    // Generate fullscreen triangle vertices from vertex index
    //   idx=0: (-1, -1) uv=(0, 0)
    //   idx=1: ( 3, -1) uv=(2, 0)
    //   idx=2: (-1,  3) uv=(0, 2)
    // The triangle covers [-1,1]x[-1,1]; fragments outside are clipped.
    outUV = vec2((gl_VertexIndex << 1) & 2, gl_VertexIndex & 2);
    gl_Position = vec4(outUV * 2.0 - 1.0, 0.0, 1.0);
}

// Pictor — Separable Gaussian Blur (Compute Shader)
// Single-direction blur pass. Run twice (horizontal + vertical) for full 2D blur.
// Uses shared memory for efficient neighborhood access.

#version 450

layout(local_size_x = 256, local_size_y = 1, local_size_z = 1) in;

layout(set = 0, binding = 0) uniform sampler2D inputTexture;
layout(set = 0, binding = 1, rgba16f) uniform writeonly image2D outputImage;

layout(push_constant) uniform BlurParams {
    vec2  direction;     // (1/w, 0) for horizontal, (0, 1/h) for vertical
    int   kernelRadius;  // half kernel size (kernel_size / 2)
    float intensity;
};

// Kernel weights uploaded via SSBO
layout(std430, set = 0, binding = 2) readonly buffer KernelWeights {
    float weights[];
};

// Shared memory tile for cooperative loading
// Max supported kernel radius = 63 (kernel_size = 127)
// Tile size = workgroup_size + 2 * max_radius = 256 + 126 = 382
shared vec4 sharedTile[382];

void main() {
    ivec2 outputSize = imageSize(outputImage);
    int lineLength = (direction.x > 0.0) ? outputSize.x : outputSize.y;
    int lineIndex  = (direction.x > 0.0)
        ? int(gl_WorkGroupID.y)
        : int(gl_WorkGroupID.x);

    if (lineIndex >= ((direction.x > 0.0) ? outputSize.y : outputSize.x))
        return;

    int localIdx = int(gl_LocalInvocationID.x);
    int tileStart = int(gl_WorkGroupID.x) * 256 - kernelRadius;

    // Cooperative load: each thread loads 1-2 elements into shared memory
    int tileSize = 256 + 2 * kernelRadius;
    for (int i = localIdx; i < tileSize; i += 256) {
        int samplePos = tileStart + i;
        samplePos = clamp(samplePos, 0, lineLength - 1);

        vec2 uv;
        if (direction.x > 0.0) {
            uv = (vec2(samplePos, lineIndex) + 0.5) / vec2(outputSize);
        } else {
            uv = (vec2(lineIndex, samplePos) + 0.5) / vec2(outputSize);
        }

        sharedTile[i] = textureLod(inputTexture, uv, 0.0);
    }

    barrier();

    // Compute output pixel position
    int globalPos = int(gl_WorkGroupID.x) * 256 + localIdx;
    if (globalPos >= lineLength) return;

    // Weighted sum using kernel weights from shared memory
    vec4 result = vec4(0.0);
    int kernelSize = 2 * kernelRadius + 1;

    for (int k = 0; k < kernelSize; ++k) {
        int tileIdx = localIdx + k;  // offset from tile start = localIdx + (k - radius) + radius
        result += sharedTile[tileIdx] * weights[k];
    }

    result.rgb *= intensity;

    ivec2 pixel;
    if (direction.x > 0.0) {
        pixel = ivec2(globalPos, lineIndex);
    } else {
        pixel = ivec2(lineIndex, globalPos);
    }

    if (pixel.x < outputSize.x && pixel.y < outputSize.y) {
        imageStore(outputImage, pixel, result);
    }
}

// Pictor — Tone Mapping Fragment Shader
// Maps HDR color to displayable LDR range with multiple operator choices.
// Also applies exposure, saturation adjustment, and gamma correction.

#version 450

layout(location = 0) in vec2 inUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D hdrInput;

layout(push_constant) uniform ToneMapParams {
    uint  tonemapOperator;   // 0=ACES, 1=Reinhard, 2=ReinhardExt, 3=Uncharted2, 4=Linear
    float exposure;
    float gamma;
    float whitePoint;
    float saturation;
};

// ---- Tone Mapping Operators ----

// ACES filmic (Narkowicz 2015 approximation)
vec3 toneMapACES(vec3 color) {
    const float a = 2.51;
    const float b = 0.03;
    const float c = 2.43;
    const float d = 0.59;
    const float e = 0.14;
    return clamp((color * (a * color + b)) / (color * (c * color + d) + e), 0.0, 1.0);
}

// Simple Reinhard (luminance-based)
vec3 toneMapReinhard(vec3 color) {
    float lum = dot(color, vec3(0.2126, 0.7152, 0.0722));
    float mapped = lum / (1.0 + lum);
    return color * (mapped / max(lum, 0.0001));
}

// Extended Reinhard with white point
vec3 toneMapReinhardExtended(vec3 color, float wp) {
    float lum = dot(color, vec3(0.2126, 0.7152, 0.0722));
    float wp2 = wp * wp;
    float numer = lum * (1.0 + lum / wp2);
    float mapped = numer / (1.0 + lum);
    return color * (mapped / max(lum, 0.0001));
}

// Uncharted 2 / Hable filmic helper
vec3 uncharted2Partial(vec3 x) {
    const float A = 0.15;  // Shoulder strength
    const float B = 0.50;  // Linear strength
    const float C = 0.10;  // Linear angle
    const float D = 0.20;  // Toe strength
    const float E = 0.02;  // Toe numerator
    const float F = 0.30;  // Toe denominator
    return ((x * (A * x + C * B) + D * E) / (x * (A * x + B) + D * F)) - E / F;
}

vec3 toneMapUncharted2(vec3 color) {
    const float W = 11.2;  // Linear white point
    vec3 curr = uncharted2Partial(color * 2.0);
    vec3 whiteScale = vec3(1.0) / uncharted2Partial(vec3(W));
    return curr * whiteScale;
}

void main() {
    vec3 color = texture(hdrInput, inUV).rgb;

    // Apply exposure
    color *= exposure;

    // Apply selected tone mapping operator
    switch (tonemapOperator) {
        case 0u: color = toneMapACES(color);                          break;
        case 1u: color = toneMapReinhard(color);                      break;
        case 2u: color = toneMapReinhardExtended(color, whitePoint);  break;
        case 3u: color = toneMapUncharted2(color);                    break;
        case 4u: color = clamp(color, 0.0, 1.0);                     break;
    }

    // Saturation adjustment (post-tonemap)
    float gray = dot(color, vec3(0.2126, 0.7152, 0.0722));
    color = mix(vec3(gray), color, saturation);

    // Gamma correction (linear → sRGB)
    color = pow(color, vec3(1.0 / gamma));

    outColor = vec4(color, 1.0);
}

// Pictor — Shadow Depth Fragment Shader
// For opaque objects this shader is a no-op (depth-only write).
// For alpha-tested materials, samples the albedo alpha and discards
// fragments below the cutoff threshold.

#version 450

// ============================================================
// Fragment Input
// ============================================================

layout(location = 0) in vec2 fragTexCoord;
layout(location = 1) in vec3 fragWorldNormal;

// ============================================================
// Material Texture (only bound for alpha-tested materials)
// ============================================================

layout(set = 1, binding = 0) uniform sampler2D albedoMap;

// ============================================================
// Push Constants (shared with vertex shader)
// ============================================================

layout(push_constant) uniform ShadowPushConstants {
    mat4  model;
    mat4  normalMatrix;
    uint  cascadeIndex;
    uint  materialFlags;         // bit 0 = ALPHA_TEST
    float alphaCutoff;
    uint  pad0;
};

void main() {
    // Alpha test: discard transparent fragments
    if ((materialFlags & 1u) != 0u) {
        float alpha = texture(albedoMap, fragTexCoord).a;
        if (alpha < alphaCutoff) {
            discard;
        }
    }

    // Depth is written automatically by the fixed-function pipeline.
    // No color output needed for shadow depth pass.
}

// Pictor — Shadow Depth Vertex Shader
// Renders geometry from the light's perspective into the shadow atlas.
// Supports cascaded shadow maps (CSM) via push constant cascade index.
// Alpha-tested materials pass through UV for fragment discard.

#version 450
#extension GL_GOOGLE_include_directive : require

// ============================================================
// Cascade Uniforms (set = 0, binding = 0)
// ============================================================

layout(set = 0, binding = 0) uniform ShadowCascadeParams {
    mat4  lightViewProj[4];      // per-cascade light VP matrices
    vec4  cascadeSplits;         // view-space split distances
    uint  cascadeCount;
    float depthBias;
    float normalBias;
    float slopeScaleBias;
};

// ============================================================
// Per-Object Push Constants
// ============================================================

layout(push_constant) uniform ShadowPushConstants {
    mat4  model;
    mat4  normalMatrix;          // transpose(inverse(model)), upper 3x3
    uint  cascadeIndex;          // which cascade this draw targets
    uint  materialFlags;         // bit 0 = ALPHA_TEST, bit 1 = TWO_SIDED
    float alphaCutoff;
    uint  pad0;
};

// ============================================================
// Vertex Input
// ============================================================

layout(location = 0) in vec3 inPosition;
layout(location = 1) in vec3 inNormal;
layout(location = 2) in vec4 inTangent;
layout(location = 3) in vec2 inTexCoord0;

// ============================================================
// Vertex Output
// ============================================================

layout(location = 0) out vec2 fragTexCoord;
layout(location = 1) out vec3 fragWorldNormal;

void main() {
    vec4 worldPos = model * vec4(inPosition, 1.0);

    // Apply normal-based bias to reduce self-shadowing (peter-panning tradeoff)
    mat3 nMat = mat3(normalMatrix);
    vec3 worldNormal = normalize(nMat * inNormal);

    // Offset position along normal to reduce shadow acne
    worldPos.xyz += worldNormal * normalBias;

    fragTexCoord = inTexCoord0;
    fragWorldNormal = worldNormal;

    gl_Position = lightViewProj[cascadeIndex] * worldPos;

    // Apply slope-scale depth bias
    // Vulkan depth range [0, 1], apply constant bias in clip space
    gl_Position.z += depthBias + slopeScaleBias * abs(gl_Position.z);
    gl_Position.z = clamp(gl_Position.z, 0.0, gl_Position.w);
}

// Pictor — Cascaded Shadow Map Generation Shader
// Pre-generates a shadow depth atlas from the directional light's perspective.
// Each cascade renders objects into its own region of the shadow atlas.
// Operates independently of material/fragment shaders.

#version 450

layout(local_size_x = 256) in;

// Per-cascade light-space view-projection
layout(set = 0, binding = 0) uniform ShadowParams {
    mat4  lightViewProj[4];   // up to 4 CSM cascades
    vec4  cascadeSplits;      // near-plane split distances (view-space Z)
    uint  objectCount;
    uint  cascadeCount;       // active cascade count (1..4)
    uint  shadowResolution;   // per-cascade resolution (e.g. 2048)
    float depthBias;
    float normalBias;
    float padding0;
    float padding1;
    float padding2;
};

// Input: world-space AABB bounds (pairs of [min, max])
layout(std430, set = 0, binding = 1) readonly buffer Bounds {
    vec4 gpu_bounds[];
};

// Input: world-space transforms
layout(std430, set = 0, binding = 2) readonly buffer Transforms {
    mat4 gpu_transforms[];
};

// Input: object visibility from culling pass
layout(std430, set = 0, binding = 3) readonly buffer Visibility {
    uint gpu_visibility[];
};

// Output: per-object shadow-cascade membership (bitmask per object)
// bit 0 = cascade 0, bit 1 = cascade 1, etc.
layout(std430, set = 0, binding = 4) writeonly buffer ShadowCascadeFlags {
    uint shadow_cascade_flags[];
};

// Output: light-space depth for each object × cascade
// Layout: [obj0_c0, obj0_c1, obj0_c2, obj0_c3, obj1_c0, ...]
layout(std430, set = 0, binding = 5) writeonly buffer ShadowDepths {
    float shadow_depths[];
};

// Test if an AABB is inside a cascade's light frustum
bool testCascadeFrustum(vec3 aabbMin, vec3 aabbMax, mat4 lvp) {
    // Project all 8 corners into light clip space
    // If all corners are outside any single clip plane, AABB is outside
    bool allOutside[6] = bool[6](true, true, true, true, true, true);

    for (int c = 0; c < 8; c++) {
        vec3 corner = vec3(
            ((c & 1) != 0) ? aabbMax.x : aabbMin.x,
            ((c & 2) != 0) ? aabbMax.y : aabbMin.y,
            ((c & 4) != 0) ? aabbMax.z : aabbMin.z
        );

        vec4 clip = lvp * vec4(corner, 1.0);

        // Check each clip plane
        if (clip.x >= -clip.w) allOutside[0] = false; // +X
        if (clip.x <=  clip.w) allOutside[1] = false; // -X
        if (clip.y >= -clip.w) allOutside[2] = false; // +Y
        if (clip.y <=  clip.w) allOutside[3] = false; // -Y
        if (clip.z >= 0.0)     allOutside[4] = false; // near (Vulkan: 0..1)
        if (clip.z <=  clip.w) allOutside[5] = false; // far
    }

    for (int i = 0; i < 6; i++) {
        if (allOutside[i]) return false;
    }
    return true;
}

// Compute the minimum light-space depth of an AABB
float computeLightDepth(vec3 aabbMin, vec3 aabbMax, mat4 lvp) {
    float minDepth = 1.0;

    for (int c = 0; c < 8; c++) {
        vec3 corner = vec3(
            ((c & 1) != 0) ? aabbMax.x : aabbMin.x,
            ((c & 2) != 0) ? aabbMax.y : aabbMin.y,
            ((c & 4) != 0) ? aabbMax.z : aabbMin.z
        );

        vec4 clip = lvp * vec4(corner, 1.0);
        if (clip.w > 0.0) {
            float depth = clip.z / clip.w;
            minDepth = min(minDepth, depth);
        }
    }

    return clamp(minDepth + depthBias, 0.0, 1.0);
}

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    // Skip invisible objects
    if (gpu_visibility[idx] == 0) {
        shadow_cascade_flags[idx] = 0u;
        for (uint c = 0; c < 4; c++) {
            shadow_depths[idx * 4 + c] = 1.0;
        }
        return;
    }

    vec3 aabbMin = gpu_bounds[idx * 2].xyz;
    vec3 aabbMax = gpu_bounds[idx * 2 + 1].xyz;

    uint cascadeMask = 0u;

    for (uint c = 0; c < cascadeCount; c++) {
        bool inCascade = testCascadeFrustum(aabbMin, aabbMax, lightViewProj[c]);

        if (inCascade) {
            cascadeMask |= (1u << c);
            shadow_depths[idx * 4 + c] = computeLightDepth(aabbMin, aabbMax, lightViewProj[c]);
        } else {
            shadow_depths[idx * 4 + c] = 1.0;
        }
    }

    // Fill unused cascade slots
    for (uint c = cascadeCount; c < 4; c++) {
        shadow_depths[idx * 4 + c] = 1.0;
    }

    shadow_cascade_flags[idx] = cascadeMask;
}

#version 450

// GPU Compute Shader for Skeletal Animation Skinning
// Computes skinned vertex positions in parallel on the GPU.
// Each invocation processes one vertex, applying bone influences.

layout(local_size_x = 256) in;

// Skinning matrices (one per bone, max 256 bones)
layout(std430, binding = 0) readonly buffer BoneMatrices {
    mat4 bone_matrices[];
};

// Input vertex positions (bind pose)
layout(std430, binding = 1) readonly buffer InputPositions {
    vec4 in_positions[];
};

// Input vertex normals (bind pose)
layout(std430, binding = 2) readonly buffer InputNormals {
    vec4 in_normals[];
};

// Joint indices (4 per vertex, packed as uvec4)
layout(std430, binding = 3) readonly buffer JointIndices {
    uvec4 joint_indices[];
};

// Joint weights (4 per vertex)
layout(std430, binding = 4) readonly buffer JointWeights {
    vec4 joint_weights[];
};

// Output skinned positions
layout(std430, binding = 5) writeonly buffer OutputPositions {
    vec4 out_positions[];
};

// Output skinned normals
layout(std430, binding = 6) writeonly buffer OutputNormals {
    vec4 out_normals[];
};

// Push constants
layout(push_constant) uniform PushConstants {
    uint vertex_count;
    uint bone_count;
    uint pad0;
    uint pad1;
} pc;

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= pc.vertex_count) return;

    vec4 pos = in_positions[idx];
    vec4 norm = in_normals[idx];
    uvec4 joints = joint_indices[idx];
    vec4 weights = joint_weights[idx];

    // Compute skinned position and normal
    vec4 skinned_pos = vec4(0.0);
    vec4 skinned_norm = vec4(0.0);

    // Bone influence 0
    if (weights.x > 0.0) {
        mat4 m = bone_matrices[joints.x];
        skinned_pos  += m * pos * weights.x;
        skinned_norm += m * vec4(norm.xyz, 0.0) * weights.x;
    }

    // Bone influence 1
    if (weights.y > 0.0) {
        mat4 m = bone_matrices[joints.y];
        skinned_pos  += m * pos * weights.y;
        skinned_norm += m * vec4(norm.xyz, 0.0) * weights.y;
    }

    // Bone influence 2
    if (weights.z > 0.0) {
        mat4 m = bone_matrices[joints.z];
        skinned_pos  += m * pos * weights.z;
        skinned_norm += m * vec4(norm.xyz, 0.0) * weights.z;
    }

    // Bone influence 3
    if (weights.w > 0.0) {
        mat4 m = bone_matrices[joints.w];
        skinned_pos  += m * pos * weights.w;
        skinned_norm += m * vec4(norm.xyz, 0.0) * weights.w;
    }

    // Normalize the skinned normal
    skinned_norm.xyz = normalize(skinned_norm.xyz);
    skinned_norm.w = 0.0;
    skinned_pos.w = 1.0;

    out_positions[idx] = skinned_pos;
    out_normals[idx] = skinned_norm;
}

// Pictor — Screen-Space Ambient Occlusion (SSAO) Generation Shader
// Generates an occlusion map from the depth buffer and view-space normals.
// Uses hemisphere sampling with random rotation to detect nearby geometry
// that blocks ambient light. Output is a single-channel occlusion texture.
// Independent of material shaders — reads only depth/normal G-buffer.

#version 450

layout(local_size_x = 16, local_size_y = 16) in;

layout(set = 0, binding = 0) uniform SSAOParams {
    mat4  projection;
    mat4  invProjection;
    uvec2 screenSize;
    float radius;           // world-space hemisphere radius
    float bias;             // angle bias to reduce self-occlusion
    float intensity;        // occlusion strength multiplier
    uint  sampleCount;      // kernel samples (typically 32 or 64)
    float falloffStart;     // distance at which AO starts to fall off
    float falloffEnd;       // distance at which AO reaches zero
};

// Hemisphere sample kernel (pre-computed on CPU, cosine-weighted)
layout(std430, set = 0, binding = 1) readonly buffer SampleKernel {
    vec4 samples[];  // xyz = direction, w = scale factor
};

// Input: depth buffer from depth pre-pass
layout(set = 0, binding = 2) uniform sampler2D depthTexture;

// Input: view-space normals (from G-buffer or reconstructed)
layout(set = 0, binding = 3) uniform sampler2D normalTexture;

// Input: 4x4 rotation noise texture (tiled across screen)
layout(set = 0, binding = 4) uniform sampler2D noiseTexture;

// Output: single-channel AO map
layout(set = 0, binding = 5, r8) writeonly uniform image2D aoOutput;

// Reconstruct view-space position from depth
vec3 reconstructViewPos(vec2 uv, float depth) {
    // NDC: Vulkan uses [0,1] depth range
    vec4 clipPos = vec4(uv * 2.0 - 1.0, depth, 1.0);
    vec4 viewPos = invProjection * clipPos;
    return viewPos.xyz / viewPos.w;
}

void main() {
    uvec2 pos = gl_GlobalInvocationID.xy;
    if (pos.x >= screenSize.x || pos.y >= screenSize.y) return;

    vec2 uv = (vec2(pos) + 0.5) / vec2(screenSize);

    // Sample depth and reconstruct view-space position
    float depth = texture(depthTexture, uv).r;

    // Skip far plane (sky)
    if (depth >= 1.0) {
        imageStore(aoOutput, ivec2(pos), vec4(1.0));
        return;
    }

    vec3 viewPos = reconstructViewPos(uv, depth);

    // Distance-based falloff: skip very distant fragments
    float dist = -viewPos.z; // positive distance in view space
    if (dist > falloffEnd) {
        imageStore(aoOutput, ivec2(pos), vec4(1.0));
        return;
    }

    // Read view-space normal
    vec3 normal = normalize(texture(normalTexture, uv).xyz * 2.0 - 1.0);

    // Rotation vector from 4x4 noise tile
    vec2 noiseUV = vec2(pos) / 4.0; // 4x4 tile
    vec3 randomVec = normalize(texture(noiseTexture, noiseUV).xyz * 2.0 - 1.0);

    // Build TBN (tangent-bitangent-normal) from normal + randomVec
    vec3 tangent   = normalize(randomVec - normal * dot(randomVec, normal));
    vec3 bitangent = cross(normal, tangent);
    mat3 TBN       = mat3(tangent, bitangent, normal);

    // Accumulate occlusion from hemisphere samples
    float occlusion = 0.0;

    for (uint i = 0; i < sampleCount; i++) {
        // Transform sample from tangent space to view space
        vec3 sampleDir = TBN * samples[i].xyz;
        vec3 samplePos = viewPos + sampleDir * radius * samples[i].w;

        // Project sample to screen space
        vec4 sampleClip = projection * vec4(samplePos, 1.0);
        vec2 sampleUV   = (sampleClip.xy / sampleClip.w) * 0.5 + 0.5;

        // Bounds check
        if (sampleUV.x < 0.0 || sampleUV.x > 1.0 ||
            sampleUV.y < 0.0 || sampleUV.y > 1.0) {
            continue;
        }

        // Sample depth at the projected position
        float sampleDepth = texture(depthTexture, sampleUV).r;
        vec3  sampleViewPos = reconstructViewPos(sampleUV, sampleDepth);

        // Range check: only occlude if the sampled geometry is close enough
        float rangeCheck = smoothstep(0.0, 1.0,
            radius / abs(viewPos.z - sampleViewPos.z));

        // Occlusion test: is the sample behind existing geometry?
        float occluded = (sampleViewPos.z >= samplePos.z + bias) ? 1.0 : 0.0;
        occlusion += occluded * rangeCheck;
    }

    occlusion = 1.0 - (occlusion / float(sampleCount)) * intensity;

    // Distance-based falloff
    float distFade = 1.0 - smoothstep(falloffStart, falloffEnd, dist);
    occlusion = mix(1.0, occlusion, distFade);

    occlusion = clamp(occlusion, 0.0, 1.0);

    imageStore(aoOutput, ivec2(pos), vec4(occlusion));
}

// Pictor — Static Object AO Bake Shader
// Computes per-object ambient occlusion for the static pool by testing
// each object's position against surrounding geometry AABBs.
// Unlike screen-space SSAO, this is view-independent and uses
// a high sample count for offline-quality results.

#version 450

layout(local_size_x = 256) in;

layout(set = 0, binding = 0) uniform BakeAOParams {
    uint  objectCount;
    uint  totalSceneObjects;  // all static objects for intersection
    uint  sampleCount;        // hemisphere sample directions
    float radius;             // max occlusion test radius
    float bias;
    float intensity;
    float padding0;
    float padding1;
};

// Input: world-space AABB bounds of bake targets
layout(std430, set = 0, binding = 1) readonly buffer BakeBounds {
    vec4 bake_bounds[];  // pairs: [min, max]
};

// Input: all static scene AABB bounds (occluders)
layout(std430, set = 0, binding = 2) readonly buffer SceneBounds {
    vec4 scene_bounds[];  // pairs: [min, max]
};

// Input: hemisphere sample directions (cosine-weighted)
layout(std430, set = 0, binding = 3) readonly buffer SampleDirs {
    vec4 sample_dirs[];  // xyz = direction, w = weight
};

// Output: per-object AO value
layout(std430, set = 0, binding = 4) writeonly buffer AOOutput {
    float ao_values[];
};

// Ray-AABB intersection test (slab method)
bool rayIntersectsAABB(vec3 origin, vec3 invDir, vec3 aabbMin, vec3 aabbMax,
                       float maxDist) {
    vec3 t1 = (aabbMin - origin) * invDir;
    vec3 t2 = (aabbMax - origin) * invDir;

    vec3 tMin = min(t1, t2);
    vec3 tMax = max(t1, t2);

    float tNear = max(max(tMin.x, tMin.y), tMin.z);
    float tFar  = min(min(tMax.x, tMax.y), tMax.z);

    return tFar >= max(tNear, 0.0) && tNear < maxDist;
}

void main() {
    uint idx = gl_GlobalInvocationID.x;
    if (idx >= objectCount) return;

    vec3 aabbMin = bake_bounds[idx * 2].xyz;
    vec3 aabbMax = bake_bounds[idx * 2 + 1].xyz;
    vec3 center  = (aabbMin + aabbMax) * 0.5;

    float occlusion = 0.0;

    for (uint s = 0; s < sampleCount; s++) {
        vec3 dir = sample_dirs[s].xyz;
        float weight = sample_dirs[s].w;

        // Offset ray origin slightly to avoid self-intersection
        vec3 origin = center + dir * bias;
        vec3 invDir = 1.0 / (dir + vec3(1e-8)); // avoid div-by-zero

        bool occluded = false;

        // Test against all scene objects (brute-force for correctness)
        for (uint j = 0; j < totalSceneObjects; j++) {
            if (j == idx) continue; // skip self

            vec3 sceneMin = scene_bounds[j * 2].xyz;
            vec3 sceneMax = scene_bounds[j * 2 + 1].xyz;

            if (rayIntersectsAABB(origin, invDir, sceneMin, sceneMax, radius)) {
                occluded = true;
                break;
            }
        }

        if (occluded) {
            occlusion += weight;
        }
    }

    // Normalize and invert: 1.0 = fully open, 0.0 = fully occluded
    float totalWeight = 0.0;
    for (uint s = 0; s < sampleCount; s++) {
        totalWeight += sample_dirs[s].w;
    }

    float ao = 1.0 - (occlusion / max(totalWeight, 1e-6)) * intensity;
    ao_values[idx] = clamp(ao, 0.0, 1.0);
}

// Pictor — Toon Fragment Shader
// Cel-shading with configurable band count, rim lighting, and specular highlight.
// Outline pass outputs a solid color (combined with front-face culling).

#version 450
#extension GL_GOOGLE_include_directive : require

#include "common.glsl"
#include "shadow.glsl"

// ============================================================
// Specialization Constants
// ============================================================

layout(constant_id = 0) const uint OUTLINE_PASS = 0;

// ============================================================
// Fragment Input
// ============================================================

layout(location = 0) in vec3 fragWorldPos;
layout(location = 1) in vec2 fragTexCoord;
layout(location = 2) in vec3 fragNormal;
layout(location = 3) in vec3 fragViewDir;

// ============================================================
// Material Textures (set = 1)
// ============================================================

layout(set = 1, binding = 0) uniform sampler2D albedoMap;
layout(set = 1, binding = 1) uniform sampler2D rampMap;         // 1D shading ramp (optional)

// ============================================================
// Material Parameters (set = 1, binding = 5)
// ============================================================

layout(set = 1, binding = 5) uniform MaterialParams {
    vec4  baseColorFactor;
    float shadowThreshold;     // NdotL threshold for shadow band (default 0.0)
    float shadowSmoothness;    // anti-alias width for shadow edge
    uint  bandCount;           // number of discrete shading bands (2-8)
    float specularSize;        // specular highlight size (0.0-1.0)
    float specularSmoothness;  // specular edge smoothness
    float rimPower;            // rim light exponent
    float rimStrength;         // rim light intensity
    uint  receiveShadow;       // 1 = sample shadow map, 0 = skip
};

// ============================================================
// Toon Outline Parameters (set = 1, binding = 6)
// ============================================================

layout(set = 1, binding = 6) uniform ToonParams {
    vec4  outlineColor;
    float outlineWidth;
    float pad5, pad6, pad7;
};

// ============================================================
// Output
// ============================================================

layout(location = 0) out vec4 outColor;

// ============================================================
// Toon Shading Functions
// ============================================================

// Quantize a value into discrete bands
float quantize(float value, uint bands) {
    float stepped = floor(value * float(bands)) / float(bands);
    return stepped;
}

// Smooth step between shadow and lit regions
float toonDiffuse(float NdotL) {
    // Method 1: Band-based quantization
    float lit = clamp((NdotL - shadowThreshold) / (shadowSmoothness + EPSILON)
                      * 0.5 + 0.5, 0.0, 1.0);
    return quantize(lit, bandCount);
}

// Ramp-based shading (sample from 1D ramp texture)
float toonDiffuseRamp(float NdotL) {
    float u = NdotL * 0.5 + 0.5; // remap [-1,1] -> [0,1]
    return texture(rampMap, vec2(u, 0.5)).r;
}

// Toon specular highlight (hard-edged)
float toonSpecular(vec3 N, vec3 H) {
    float NdotH = max(dot(N, H), 0.0);
    float spec  = pow(NdotH, 1.0 / (specularSize + EPSILON));
    return smoothstep(0.5 - specularSmoothness, 0.5 + specularSmoothness, spec);
}

// Rim lighting (Fresnel-based edge glow)
float rimLight(vec3 N, vec3 V) {
    float NdotV = max(dot(N, V), 0.0);
    return pow(1.0 - NdotV, rimPower) * rimStrength;
}

void main() {
    // ---- Outline pass: solid color output ----
    if (OUTLINE_PASS == 1) {
        outColor = outlineColor;
        return;
    }

    // ---- Main toon shading ----
    vec3 N = normalize(fragNormal);
    vec3 V = normalize(fragViewDir);

    // Sample albedo
    vec4 albedoSample = texture(albedoMap, fragTexCoord);
    vec3 albedo = albedoSample.rgb * baseColorFactor.rgb;
    float alpha = albedoSample.a * baseColorFactor.a;

    // Compute shadow factor
    float shadow = 1.0;
    if (receiveShadow != 0u) {
        vec4 viewPos = view * vec4(fragWorldPos, 1.0);
        float viewDepth = -viewPos.z;
        vec3 sunDir = normalize(sun.direction.xyz);
        shadow = sampleShadow(fragWorldPos, viewDepth, N, sunDir);
    }

    vec3 Lo = vec3(0.0);

    // Directional light (sun) — modulated by shadow
    {
        vec3 L = normalize(sun.direction.xyz);
        vec3 H = normalize(V + L);
        float NdotL = dot(N, L);

        float diffuse = toonDiffuse(NdotL);
        float spec    = toonSpecular(N, H);

        vec3 lightColor = sun.color.rgb * sun.color.a;
        Lo += albedo * lightColor * diffuse * shadow;
        Lo += lightColor * spec * shadow;
    }

    // Point lights
    for (uint i = 0; i < activePointLights; i++) {
        vec3 lightVec = pointLights[i].position.xyz - fragWorldPos;
        float dist    = length(lightVec);
        vec3 L        = lightVec / dist;
        vec3 H        = normalize(V + L);
        float NdotL   = dot(N, L);

        float atten   = attenuatePoint(dist, pointLights[i].position.w);
        float diffuse = toonDiffuse(NdotL);
        float spec    = toonSpecular(N, H);

        vec3 lightColor = pointLights[i].color.rgb * pointLights[i].color.a * atten;
        Lo += albedo * lightColor * diffuse;
        Lo += lightColor * spec;
    }

    // Rim lighting
    float rim = rimLight(N, V);
    Lo += albedo * rim;

    // Ambient
    vec3 ambient = albedo * ambientColor.rgb * ambientColor.a;

    vec3 color = ambient + Lo;

    // Gamma correction (toon shading typically works in sRGB space directly)
    color = linearToSrgb(color);

    outColor = vec4(color, alpha);
}

// Pictor — Toon Vertex Shader
// Standard transform + outline pass support via vertex extrusion.

#version 450
#extension GL_GOOGLE_include_directive : require

#include "common.glsl"

// ============================================================
// Specialization Constants
// ============================================================

// Set to 1 to enable outline extrusion pass
layout(constant_id = 0) const uint OUTLINE_PASS = 0;

// ============================================================
// Vertex Input
// ============================================================

layout(location = 0) in vec3 inPosition;
layout(location = 1) in vec3 inNormal;
layout(location = 2) in vec4 inTangent;
layout(location = 3) in vec2 inTexCoord0;

// ============================================================
// Vertex Output
// ============================================================

layout(location = 0) out vec3 fragWorldPos;
layout(location = 1) out vec2 fragTexCoord;
layout(location = 2) out vec3 fragNormal;
layout(location = 3) out vec3 fragViewDir;

// ============================================================
// Toon Outline Parameters (set = 1, binding = 6)
// ============================================================

layout(set = 1, binding = 6) uniform ToonParams {
    vec4  outlineColor;        // RGB = color, A = unused
    float outlineWidth;        // world-space extrusion width
    float pad5, pad6, pad7;
};

void main() {
    mat3 nMat = mat3(normalMatrix);
    vec3 worldNormal = normalize(nMat * inNormal);

    vec3 pos = inPosition;

    // Outline pass: extrude vertices along normal direction
    if (OUTLINE_PASS == 1) {
        pos += inNormal * outlineWidth;
    }

    vec4 worldPos = model * vec4(pos, 1.0);

    fragWorldPos = worldPos.xyz;
    fragTexCoord = inTexCoord0;
    fragNormal   = worldNormal;
    fragViewDir  = normalize(cameraPosition.xyz - worldPos.xyz);

    gl_Position = viewProjection * worldPos;
}

#version 450

// UI Overlay fragment shader — texture * per-vertex color

layout(set = 0, binding = 0) uniform sampler2D u_texture;

layout(location = 0) in vec2 v_texCoord;
layout(location = 1) in vec4 v_color;

layout(location = 0) out vec4 fragColor;

void main() {
    vec4 texel  = texture(u_texture, v_texCoord);
    fragColor   = texel * v_color;
}

#version 450

// UI Overlay vertex shader — per-vertex color, pre-transformed NDC positions

layout(location = 0) in vec2  a_position;  // NDC [-1, 1]
layout(location = 1) in vec2  a_texCoord;
layout(location = 2) in vec4  a_color;     // RGBA tint

layout(location = 0) out vec2 v_texCoord;
layout(location = 1) out vec4 v_color;

void main() {
    gl_Position = vec4(a_position, 0.0, 1.0);
    v_texCoord  = a_texCoord;
    v_color     = a_color;
}

// Pictor — UI Widget Fragment Shader
// mode に応じて 角丸矩形 / テクスチャ画像 / 9-slice を描く。
//   mode 0 = Rect (角丸、 純色)
//   mode 1 = Image (テクスチャ * tint)
//   mode 2 = NineSlice (9-slice UV リマップ後にサンプル)

#version 450

layout(location = 0) in vec2 inUV;
layout(location = 1) in vec2 inLocalPx;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D tex;

layout(push_constant) uniform PC {
    vec4 rect;       // x, y, w, h
    vec4 color;      // rgba
    vec4 params;     // corner_radius, mode, opacity, _pad
    vec4 nine;       // 9-slice insets l, t, r, b (px)
    vec4 viewport;
};

// 角丸矩形の signed distance。
float rounded_box_sdf(vec2 p, vec2 half_size, float radius) {
    vec2 q = abs(p) - half_size + radius;
    return min(max(q.x, q.y), 0.0) + length(max(q, 0.0)) - radius;
}

// 1 軸の 9-slice UV リマップ。 size = rect の該当軸長、 lo/hi = inset。
float nine_axis(float uv, float size, float lo, float hi) {
    float px = uv * size;
    if (px < lo)             return px;                       // 左/上の固定帯
    if (px > size - hi)      return px - (size - hi) + lo;     // 右/下の固定帯 (テクスチャ末尾基準は別途)
    // 中央帯: lo..(size-hi) を lo..(1-hi 相当) に伸縮 — ここでは簡易に
    // 中央を [lo, lo+ (mid)] でストレッチした値を返す。
    return lo + (px - lo);   // 呼び出し側で正規化する
}

void main() {
    float radius  = params.x;
    int   mode    = int(params.y + 0.5);
    float opacity = params.z;

    vec4 result;

    if (mode == 1) {
        // Image: テクスチャ * tint
        result = texture(tex, inUV) * color;
    } else if (mode == 2) {
        // NineSlice: 9-slice UV リマップ。 nine = l,t,r,b (px)。
        // テクスチャ・矩形ともに同じ inset で 3x3 に分割し、 各帯を対応付ける。
        vec2 sz = rect.zw;
        vec2 px = inUV * sz;
        // X
        float u;
        if (px.x < nine.x) {
            u = px.x / max(sz.x, 1.0);                    // 左帯 (素のまま近似)
        } else if (px.x > sz.x - nine.z) {
            u = 1.0 - (sz.x - px.x) / max(sz.x, 1.0);
        } else {
            float t = (px.x - nine.x) / max(sz.x - nine.x - nine.z, 1.0);
            u = mix(nine.x / max(sz.x, 1.0),
                    1.0 - nine.z / max(sz.x, 1.0), t);
        }
        // Y
        float v;
        if (px.y < nine.y) {
            v = px.y / max(sz.y, 1.0);
        } else if (px.y > sz.y - nine.w) {
            v = 1.0 - (sz.y - px.y) / max(sz.y, 1.0);
        } else {
            float t = (px.y - nine.y) / max(sz.y - nine.y - nine.w, 1.0);
            v = mix(nine.y / max(sz.y, 1.0),
                    1.0 - nine.w / max(sz.y, 1.0), t);
        }
        result = texture(tex, vec2(u, v)) * color;
    } else {
        // Rect: 角丸の SDF マスク。
        vec2 half_size = rect.zw * 0.5;
        vec2 p = inLocalPx - half_size;
        float d = rounded_box_sdf(p, half_size, min(radius, min(half_size.x, half_size.y)));
        float aa = fwidth(d) + 1e-4;
        float mask = 1.0 - smoothstep(-aa, aa, d);
        result = vec4(color.rgb, color.a * mask);
    }

    result.a *= opacity;
    if (result.a <= 0.0) discard;
    outColor = result;
}

// Pictor — UI Widget Vertex Shader
// push 定数の rect (px) と viewport から、 vertexIndex 0..3 で
// triangle-strip の quad を NDC に生成する。 頂点バッファ無し。

#version 450

layout(location = 0) out vec2 outUV;       // 0..1
layout(location = 1) out vec2 outLocalPx;  // rect ローカル px (SDF 用)

layout(push_constant) uniform PC {
    vec4 rect;       // x, y, w, h  (画面 px, 左上原点)
    vec4 color;      // rgba
    vec4 params;     // corner_radius, mode, opacity, _pad
    vec4 nine;       // 9-slice insets l, t, r, b (px)
    vec4 viewport;   // viewport_w, viewport_h, _pad, _pad
};

void main() {
    // triangle-strip: 0=(0,0) 1=(1,0) 2=(0,1) 3=(1,1)
    vec2 corner = vec2(float(gl_VertexIndex & 1), float((gl_VertexIndex >> 1) & 1));
    outUV       = corner;
    outLocalPx  = corner * rect.zw;

    vec2 px = rect.xy + corner * rect.zw;        // 画面 px
    vec2 ndc = (px / viewport.xy) * 2.0 - 1.0;   // Vulkan NDC (y 下向き)
    gl_Position = vec4(ndc, 0.0, 1.0);
}

#version 300 es
precision highp float;

in vec3 v_world_normal;
in vec3 v_world_pos;

uniform vec4 u_color;

out vec4 frag_color;

const vec3 LIGHT_DIR   = normalize(vec3(0.5, 1.0, 0.3));
const vec3 LIGHT_COLOR = vec3(1.0, 0.98, 0.95);
const vec3 AMBIENT     = vec3(0.15, 0.17, 0.22);

void main() {
    vec3 N = normalize(v_world_normal);
    float NdotL = max(dot(N, LIGHT_DIR), 0.0);
    float half_lambert = NdotL * 0.5 + 0.5;

    vec3 diffuse = u_color.rgb * LIGHT_COLOR * half_lambert;
    vec3 color   = AMBIENT * u_color.rgb + diffuse;

    frag_color = vec4(color, u_color.a);
}

