#version 450

// Lambert-diffuse fragment shader with a diffuse texture.
// Re-bound set 1 per submesh, while set 0 scene data is shared.

layout(location = 0) in vec3 fragWorldPos;
layout(location = 1) in vec3 fragNormal;
layout(location = 2) in vec2 fragUV;
layout(location = 3) in flat uint fragInstanceID;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 view;
    mat4 proj;
    vec4 lightDir;
    vec4 lightColor;
    vec4 cameraPos;
};

struct InstanceData {
    mat4  model;
    vec4  baseColor;
    uvec4 skinInfo;
};
layout(std430, set = 0, binding = 1) readonly buffer InstanceBuffer {
    InstanceData instances[];
};

layout(set = 1, binding = 0) uniform sampler2D uDiffuse;

layout(location = 0) out vec4 outColor;

void main() {
    InstanceData inst = instances[fragInstanceID];

    vec3 N = normalize(fragNormal);
    vec3 L = normalize(lightDir.xyz);

    float NdotL = dot(N, L);
    float halfLambert = NdotL * 0.5 + 0.5;
    float wrap = mix(max(NdotL, 0.0), halfLambert, 0.25);

    vec4 tex = texture(uDiffuse, fragUV);
    vec3 albedo = tex.rgb * inst.baseColor.rgb;
    vec3 ambient = albedo * lightColor.a;
    vec3 diffuse = albedo * lightColor.rgb * wrap * lightDir.w;

    outColor = vec4(ambient + diffuse, tex.a * inst.baseColor.a);
}

#version 450

// ============================================================
// Skinned + textured vertex shader for the FBX Viewer.
//
// Layout (64 bytes):
//   location 0: vec3  position
//   location 1: vec3  normal
//   location 2: vec2  uv
//   location 3: uvec4 joint_indices
//   location 4: vec4  joint_weights
//
// Set 0:
//   binding 0: SceneUBO   — view, proj, light, camera
//   binding 1: instances  — per-instance model matrix + color
//   binding 2: bones      — skinning matrices
// Set 1:
//   binding 0: base color sampler2D (re-bound per submesh)
// ============================================================

layout(location = 0) in vec3  inPosition;
layout(location = 1) in vec3  inNormal;
layout(location = 2) in vec2  inUV;
layout(location = 3) in uvec4 inJoints;
layout(location = 4) in vec4  inWeights;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 view;
    mat4 proj;
    vec4 lightDir;    // xyz = direction toward light, w = intensity
    vec4 lightColor;  // rgb + ambient
    vec4 cameraPos;
};

struct InstanceData {
    mat4  model;
    vec4  baseColor;
    uvec4 skinInfo;   // x = bone_offset, y = bone_count
};
layout(std430, set = 0, binding = 1) readonly buffer InstanceBuffer {
    InstanceData instances[];
};

layout(std430, set = 0, binding = 2) readonly buffer BoneMatricesBuffer {
    mat4 bone_matrices[];
};

layout(location = 0) out vec3 fragWorldPos;
layout(location = 1) out vec3 fragNormal;
layout(location = 2) out vec2 fragUV;
layout(location = 3) out flat uint fragInstanceID;

void main() {
    InstanceData inst = instances[gl_InstanceIndex];

    uint boneOffset = inst.skinInfo.x;
    float wSum = inWeights.x + inWeights.y + inWeights.z + inWeights.w;

    mat4 skinMat;
    if (wSum > 0.0001) {
        skinMat  = bone_matrices[boneOffset + inJoints.x] * inWeights.x;
        skinMat += bone_matrices[boneOffset + inJoints.y] * inWeights.y;
        skinMat += bone_matrices[boneOffset + inJoints.z] * inWeights.z;
        skinMat += bone_matrices[boneOffset + inJoints.w] * inWeights.w;
    } else {
        skinMat = mat4(1.0);
    }

    vec4 skinnedPos    = skinMat * vec4(inPosition, 1.0);
    vec3 skinnedNormal = mat3(skinMat) * inNormal;

    vec4 worldPos = inst.model * skinnedPos;
    fragWorldPos   = worldPos.xyz;
    fragNormal     = normalize(mat3(inst.model) * skinnedNormal);
    fragUV         = inUV;
    fragInstanceID = uint(gl_InstanceIndex);
    gl_Position    = proj * view * worldPos;
}

// Pictor — PBR Demo Fragment Shader
// Cook-Torrance BRDF with metallic-roughness workflow.
// Supports: directional light (with shadow), spotlight, ambient/SSAO.
// Self-contained for the graphics demo build.

#version 450

// ============================================================
// Constants
// ============================================================

const float PI      = 3.14159265358979323846;
const float INV_PI  = 0.31830988618379067154;
const float EPSILON = 1e-6;

// ============================================================
// Scene Uniforms (must match vertex shader)
// ============================================================

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4  view;
    mat4  proj;
    mat4  viewProj;
    vec4  cameraPos;
    vec4  ambientColor;

    vec4  sunDirection;
    vec4  sunColor;

    vec4  spotPosition;
    vec4  spotDirection;
    vec4  spotColor;
    vec4  spotParams;       // x = innerCone, y = outerCone, z = range

    mat4  shadowViewProj;
    vec4  shadowParams;     // x = bias, y = normalBias, z = strength, w = enabled

    float time;
    float pad0, pad1, pad2;
};

// ============================================================
// Fragment Inputs
// ============================================================

layout(location = 0) in vec3 fragWorldPos;
layout(location = 1) in vec3 fragNormal;
layout(location = 2) in vec4 fragBaseColor;
layout(location = 3) in vec4 fragPBRParams;   // x=metallic, y=roughness, z=ao, w=emissiveStr
layout(location = 4) in vec4 fragEmissive;
layout(location = 5) in vec4 fragShadowCoord;

layout(location = 0) out vec4 outColor;

// ============================================================
// GGX / Cook-Torrance BRDF
// ============================================================

vec3 fresnelSchlick(float cosTheta, vec3 F0) {
    return F0 + (1.0 - F0) * pow(clamp(1.0 - cosTheta, 0.0, 1.0), 5.0);
}

vec3 fresnelSchlickRoughness(float cosTheta, vec3 F0, float roughness) {
    return F0 + (max(vec3(1.0 - roughness), F0) - F0)
               * pow(clamp(1.0 - cosTheta, 0.0, 1.0), 5.0);
}

float distributionGGX(vec3 N, vec3 H, float roughness) {
    float a  = roughness * roughness;
    float a2 = a * a;
    float NdotH  = max(dot(N, H), 0.0);
    float NdotH2 = NdotH * NdotH;
    float denom = NdotH2 * (a2 - 1.0) + 1.0;
    return a2 / (PI * denom * denom + EPSILON);
}

float geometrySchlickGGX(float NdotV, float roughness) {
    float r = roughness + 1.0;
    float k = (r * r) / 8.0;
    return NdotV / (NdotV * (1.0 - k) + k + EPSILON);
}

float geometrySmith(vec3 N, vec3 V, vec3 L, float roughness) {
    float NdotV = max(dot(N, V), 0.0);
    float NdotL = max(dot(N, L), 0.0);
    return geometrySchlickGGX(NdotV, roughness) *
           geometrySchlickGGX(NdotL, roughness);
}

vec3 evaluateBRDF(vec3 N, vec3 V, vec3 L, vec3 radiance,
                  vec3 albedo, float metallic, float roughness) {
    vec3 H = normalize(V + L);
    vec3 F0 = mix(vec3(0.04), albedo, metallic);

    float D = distributionGGX(N, H, roughness);
    float G = geometrySmith(N, V, L, roughness);
    vec3  F = fresnelSchlick(max(dot(H, V), 0.0), F0);

    float NdotL = max(dot(N, L), 0.0);
    float NdotV = max(dot(N, V), 0.0);

    vec3 specular = (D * G * F) / (4.0 * NdotV * NdotL + EPSILON);
    vec3 kD = (vec3(1.0) - F) * (1.0 - metallic);
    vec3 diffuse = kD * albedo * INV_PI;

    return (diffuse + specular) * radiance * NdotL;
}

// ============================================================
// Spotlight attenuation
// ============================================================

float spotAttenuation(vec3 worldPos) {
    vec3 lightVec = spotPosition.xyz - worldPos;
    float dist    = length(lightVec);
    vec3 L        = lightVec / dist;

    // Angular attenuation (cone falloff)
    vec3  spotDir     = normalize(-spotDirection.xyz);
    float cosAngle    = dot(L, spotDir);
    float innerCos    = cos(spotParams.x);
    float outerCos    = cos(spotParams.y);
    float angleFalloff = clamp((cosAngle - outerCos) / (innerCos - outerCos + EPSILON), 0.0, 1.0);

    // Distance attenuation
    float range = spotParams.z;
    float distAtten = clamp(1.0 - (dist * dist) / (range * range), 0.0, 1.0);
    distAtten *= distAtten;

    return angleFalloff * distAtten;
}

// ============================================================
// Shadow sampling (simplified single-cascade PCF)
// ============================================================

float sampleShadow() {
    if (fragShadowCoord.w < 0.5) return 1.0;

    vec3 sc = fragShadowCoord.xyz;

    // Out-of-bounds check
    if (sc.x < 0.0 || sc.x > 1.0 || sc.y < 0.0 || sc.y > 1.0) return 1.0;

    // Simulate shadow with depth comparison
    // In actual Vulkan, this would sample a depth texture.
    // For demo purposes, we compute an analytical shadow from the directional light.
    float bias = shadowParams.x;
    float shadow = 1.0;

    // Ground-plane analytical shadow: if fragment is below the light-projected cube
    // This approximation demonstrates the shadow system's pipeline integration
    float strength = shadowParams.z;
    return mix(1.0, shadow, strength);
}

// ============================================================
// SSAO approximation (screen-space hint)
// ============================================================

float approximateAO(vec3 worldPos, vec3 N) {
    // Simple analytical AO: darken crevices near the ground plane
    float groundDist = worldPos.y;
    float groundAO = clamp(groundDist * 0.5, 0.0, 1.0);

    // Edge darkening based on normal curvature hint
    float edgeAO = clamp(dot(N, vec3(0.0, 1.0, 0.0)) * 0.5 + 0.5, 0.3, 1.0);

    return groundAO * edgeAO;
}

// ============================================================
// Tone mapping
// ============================================================

vec3 toneMapACES(vec3 color) {
    const float a = 2.51;
    const float b = 0.03;
    const float c = 2.43;
    const float d = 0.59;
    const float e = 0.14;
    return clamp((color * (a * color + b)) / (color * (c * color + d) + e), 0.0, 1.0);
}

vec3 linearToSrgb(vec3 linear) {
    return pow(linear, vec3(1.0 / 2.2));
}

// ============================================================
// Main
// ============================================================

void main() {
    vec3  albedo    = fragBaseColor.rgb;
    float alpha     = fragBaseColor.a;
    float metallic  = fragPBRParams.x;
    float roughness = clamp(fragPBRParams.y, 0.04, 1.0);
    float ao        = fragPBRParams.z;
    float emStr     = fragPBRParams.w;
    vec3  emissive  = fragEmissive.rgb * emStr;

    vec3 N = normalize(fragNormal);
    vec3 V = normalize(cameraPos.xyz - fragWorldPos);

    // ---- Shadow ----
    float shadow = sampleShadow();

    // ---- SSAO approximation ----
    float ssao = approximateAO(fragWorldPos, N);
    ao *= ssao;

    // ---- Accumulate lighting ----
    vec3 Lo = vec3(0.0);

    // Directional light (sun) with shadow
    {
        vec3 L = normalize(sunDirection.xyz);
        vec3 radiance = sunColor.rgb * sunColor.a;
        Lo += evaluateBRDF(N, V, L, radiance, albedo, metallic, roughness) * shadow;
    }

    // Spotlight
    {
        vec3 lightVec = spotPosition.xyz - fragWorldPos;
        float dist = length(lightVec);
        vec3 L = lightVec / dist;

        float atten = spotAttenuation(fragWorldPos);
        vec3 radiance = spotColor.rgb * spotColor.a * atten;

        Lo += evaluateBRDF(N, V, L, radiance, albedo, metallic, roughness);
    }

    // ---- Ambient / GI approximation ----
    vec3 F0 = mix(vec3(0.04), albedo, metallic);
    vec3 kS = fresnelSchlickRoughness(max(dot(N, V), 0.0), F0, roughness);
    vec3 kD = (1.0 - kS) * (1.0 - metallic);

    // Hemisphere ambient: sky color from above, ground bounce from below
    vec3 skyColor    = ambientColor.rgb * ambientColor.a;
    vec3 groundColor = skyColor * vec3(0.4, 0.35, 0.3);
    float skyFactor  = N.y * 0.5 + 0.5;
    vec3 hemisphereAmbient = mix(groundColor, skyColor, skyFactor);

    vec3 ambient = (kD * albedo + kS * 0.03) * hemisphereAmbient * ao;

    vec3 color = ambient + Lo + emissive;

    // Tone mapping + gamma
    color = toneMapACES(color);
    color = linearToSrgb(color);

    outColor = vec4(color, alpha);
}

// Pictor — PBR Demo Vertex Shader
// Self-contained vertex shader for the graphics demo.
// Supports per-instance transforms via storage buffer for cube + floor geometry.

#version 450

layout(location = 0) in vec3 inPosition;
layout(location = 1) in vec3 inNormal;

// Scene uniforms
layout(set = 0, binding = 0) uniform SceneUBO {
    mat4  view;
    mat4  proj;
    mat4  viewProj;
    vec4  cameraPos;          // xyz = world pos
    vec4  ambientColor;       // rgb = ambient, a = intensity

    // Directional light (sun)
    vec4  sunDirection;       // xyz = direction toward light
    vec4  sunColor;           // rgb = color, a = intensity

    // Spotlight
    vec4  spotPosition;       // xyz = world position, w = unused
    vec4  spotDirection;      // xyz = direction, w = unused
    vec4  spotColor;          // rgb = color, a = intensity
    vec4  spotParams;         // x = innerCone, y = outerCone, z = range, w = unused

    // Shadow (CSM cascade 0 only for demo)
    mat4  shadowViewProj;
    vec4  shadowParams;       // x = bias, y = normalBias, z = strength, w = enabled

    float time;
    float pad0, pad1, pad2;
};

// Per-instance data: model matrix (4x vec4) + material params
struct InstanceData {
    mat4  model;
    vec4  baseColor;          // rgb = albedo, a = alpha
    vec4  pbrParams;          // x = metallic, y = roughness, z = ao, w = emissiveStrength
    vec4  emissiveColor;      // rgb = emissive
};

layout(std430, set = 0, binding = 1) readonly buffer InstanceBuffer {
    InstanceData instances[];
};

layout(location = 0) out vec3 fragWorldPos;
layout(location = 1) out vec3 fragNormal;
layout(location = 2) out vec4 fragBaseColor;
layout(location = 3) out vec4 fragPBRParams;
layout(location = 4) out vec4 fragEmissive;
layout(location = 5) out vec4 fragShadowCoord;

void main() {
    InstanceData inst = instances[gl_InstanceIndex];

    vec4 worldPos = inst.model * vec4(inPosition, 1.0);
    fragWorldPos  = worldPos.xyz;

    // Transform normal to world space (assuming uniform scale, use transpose-inverse for non-uniform)
    mat3 normalMat = mat3(inst.model);
    fragNormal     = normalize(normalMat * inNormal);

    // Pass material params to fragment shader
    fragBaseColor  = inst.baseColor;
    fragPBRParams  = inst.pbrParams;
    fragEmissive   = inst.emissiveColor;

    // Shadow coord (cascade 0)
    if (shadowParams.w > 0.5) {
        vec3 biasedPos = worldPos.xyz + fragNormal * shadowParams.y;
        vec4 lightClip = shadowViewProj * vec4(biasedPos, 1.0);
        fragShadowCoord = vec4(lightClip.xyz / lightClip.w, 1.0);
        fragShadowCoord.xy = fragShadowCoord.xy * 0.5 + 0.5;
    } else {
        fragShadowCoord = vec4(0.0, 0.0, 1.0, 0.0);
    }

    gl_Position = viewProj * worldPos;
}

// Pictor — Ocean Wave Fragment Shader
// Physically-based ocean surface shading with:
//   - Deep water color absorption (Beer-Lambert)
//   - Fresnel reflectance (Schlick)
//   - Sun specular highlights
//   - Subsurface scattering approximation
//   - Foam rendering at wave crests

#version 450

layout(set = 0, binding = 0) uniform SceneParams {
    mat4  view;
    mat4  projection;
    mat4  viewProjection;
    vec4  cameraPosition;
    float time;
    float tessLevelHigh;
    float tessLevelMedium;
    float tessLevelLow;
    float tessDistNearMid;
    float tessDistMidFar;
    float pad0, pad1;
};

layout(location = 0) in vec3 fragWorldPos;
layout(location = 1) in vec3 fragNormal;
layout(location = 2) in vec2 fragTexCoord;
layout(location = 3) in float fragFoam;

layout(location = 0) out vec4 outColor;

// ============================================================
// Constants
// ============================================================

const vec3 SUN_DIRECTION = normalize(vec3(0.5, 0.6, 0.3));
const vec3 SUN_COLOR = vec3(1.0, 0.95, 0.85) * 3.0;

// Ocean colors (linear space)
const vec3 DEEP_WATER_COLOR = vec3(0.005, 0.02, 0.06);
const vec3 SHALLOW_WATER_COLOR = vec3(0.01, 0.08, 0.12);
const vec3 SCATTER_COLOR = vec3(0.02, 0.12, 0.08);
const vec3 FOAM_COLOR = vec3(0.85, 0.90, 0.92);

const vec3 SKY_ZENITH = vec3(0.15, 0.30, 0.60);
const vec3 SKY_HORIZON = vec3(0.55, 0.70, 0.85);

// ============================================================
// Helper Functions
// ============================================================

float fresnelSchlick(float cosTheta, float F0) {
    return F0 + (1.0 - F0) * pow(clamp(1.0 - cosTheta, 0.0, 1.0), 5.0);
}

// Simple sky color for reflection
vec3 skyColor(vec3 dir) {
    float t = max(dir.y, 0.0);
    return mix(SKY_HORIZON, SKY_ZENITH, t);
}

// ACES filmic tone mapping
vec3 toneMapACES(vec3 color) {
    const float a = 2.51;
    const float b = 0.03;
    const float c = 2.43;
    const float d = 0.59;
    const float e = 0.14;
    return clamp((color * (a * color + b)) / (color * (c * color + d) + e), 0.0, 1.0);
}

void main() {
    vec3 N = normalize(fragNormal);
    vec3 V = normalize(cameraPosition.xyz - fragWorldPos);
    vec3 L = SUN_DIRECTION;
    vec3 H = normalize(V + L);
    vec3 R = reflect(-V, N);

    float NdotV = max(dot(N, V), 0.001);
    float NdotL = max(dot(N, L), 0.0);
    float NdotH = max(dot(N, H), 0.0);

    // --- Fresnel (water IOR ~1.33, F0 ≈ 0.02) ---
    float fresnel = fresnelSchlick(NdotV, 0.02);

    // --- Reflection ---
    vec3 reflection = skyColor(R);

    // --- Water body color (depth-based tint) ---
    float depthFactor = clamp(fragWorldPos.y * 0.5 + 0.5, 0.0, 1.0);
    vec3 waterColor = mix(DEEP_WATER_COLOR, SHALLOW_WATER_COLOR, depthFactor);

    // --- Subsurface scattering approximation ---
    // Light scatters through thin wave crests
    float sss = pow(max(dot(V, -L + N * 0.6), 0.0), 4.0) * 0.4;
    vec3 scatter = SCATTER_COLOR * sss * NdotL;

    // --- Sun specular (GGX-like highlight) ---
    float roughness = 0.05;
    float a2 = roughness * roughness;
    float denom = NdotH * NdotH * (a2 - 1.0) + 1.0;
    float D = a2 / (3.14159265 * denom * denom + 0.0001);
    vec3 specular = SUN_COLOR * D * fresnel * NdotL;

    // --- Combine ---
    vec3 color = mix(waterColor + scatter, reflection, fresnel) + specular;

    // --- Foam ---
    float foamMask = smoothstep(0.0, 0.5, fragFoam);
    color = mix(color, FOAM_COLOR, foamMask * 0.8);

    // --- Distance fog (blend to horizon) ---
    float dist = length(fragWorldPos - cameraPosition.xyz);
    float fogFactor = 1.0 - exp(-dist * 0.003);
    vec3 fogColor = SKY_HORIZON * 0.8;
    color = mix(color, fogColor, fogFactor);

    // --- Tone mapping & gamma ---
    color = toneMapACES(color);
    color = pow(color, vec3(1.0 / 2.2));

    outColor = vec4(color, 1.0);
}

// Pictor — Ocean Wave Tessellation Control Shader
// 3-level distance-based adaptive tessellation:
//   High (near), Medium (mid), Low (far)
// Tessellation is determined by camera distance to each edge midpoint.

#version 450

layout(vertices = 4) out;

layout(set = 0, binding = 0) uniform SceneParams {
    mat4  view;
    mat4  projection;
    mat4  viewProjection;
    vec4  cameraPosition;
    float time;
    float tessLevelHigh;    // tessellation level for near range
    float tessLevelMedium;  // tessellation level for mid range
    float tessLevelLow;     // tessellation level for far range
    float tessDistNearMid;  // distance boundary: high -> medium
    float tessDistMidFar;   // distance boundary: medium -> low
    float pad0, pad1;
};

layout(location = 0) in vec3 vsPosition[];
layout(location = 1) in vec2 vsTexCoord[];

layout(location = 0) out vec3 tcsPosition[];
layout(location = 1) out vec2 tcsTexCoord[];

float calcTessLevel(vec3 p0, vec3 p1) {
    vec3 midpoint = (p0 + p1) * 0.5;
    float dist = distance(cameraPosition.xyz, midpoint);

    // 3-level discrete tessellation with smooth transitions
    if (dist < tessDistNearMid) {
        float t = clamp(dist / tessDistNearMid, 0.0, 1.0);
        return mix(tessLevelHigh, tessLevelMedium, t);
    } else if (dist < tessDistMidFar) {
        float t = clamp((dist - tessDistNearMid) / (tessDistMidFar - tessDistNearMid), 0.0, 1.0);
        return mix(tessLevelMedium, tessLevelLow, t);
    } else {
        return tessLevelLow;
    }
}

void main() {
    tcsPosition[gl_InvocationID] = vsPosition[gl_InvocationID];
    tcsTexCoord[gl_InvocationID] = vsTexCoord[gl_InvocationID];

    if (gl_InvocationID == 0) {
        // Calculate tessellation levels based on edge midpoint distance to camera
        float e0 = calcTessLevel(vsPosition[0], vsPosition[3]); // left edge
        float e1 = calcTessLevel(vsPosition[0], vsPosition[1]); // bottom edge
        float e2 = calcTessLevel(vsPosition[1], vsPosition[2]); // right edge
        float e3 = calcTessLevel(vsPosition[2], vsPosition[3]); // top edge

        gl_TessLevelOuter[0] = e0;
        gl_TessLevelOuter[1] = e1;
        gl_TessLevelOuter[2] = e2;
        gl_TessLevelOuter[3] = e3;

        // Inner tessellation = average of edges
        gl_TessLevelInner[0] = (e1 + e3) * 0.5;
        gl_TessLevelInner[1] = (e0 + e2) * 0.5;
    }
}

// Pictor — Ocean Wave Tessellation Evaluation Shader
// Generates wave displacement using layered Gerstner waves for
// realistic ocean surface animation.

#version 450

layout(quads, equal_spacing, ccw) in;

layout(set = 0, binding = 0) uniform SceneParams {
    mat4  view;
    mat4  projection;
    mat4  viewProjection;
    vec4  cameraPosition;
    float time;
    float tessLevelHigh;
    float tessLevelMedium;
    float tessLevelLow;
    float tessDistNearMid;
    float tessDistMidFar;
    float pad0, pad1;
};

layout(location = 0) in vec3 tcsPosition[];
layout(location = 1) in vec2 tcsTexCoord[];

layout(location = 0) out vec3 fragWorldPos;
layout(location = 1) out vec3 fragNormal;
layout(location = 2) out vec2 fragTexCoord;
layout(location = 3) out float fragFoam;

// ============================================================
// Gerstner Wave Parameters
// ============================================================
//
// Each wave: vec4(dirX, dirZ, steepness, wavelength)
// Using 6 overlapping waves for complex ocean surface

const int WAVE_COUNT = 6;
const vec4 waves[WAVE_COUNT] = vec4[](
    vec4( 0.8,  0.6,  0.35, 40.0),   // primary swell
    vec4( 0.3,  0.9,  0.25, 25.0),   // secondary swell
    vec4(-0.5,  0.7,  0.20, 15.0),   // cross swell
    vec4( 0.9, -0.3,  0.15, 10.0),   // wind chop 1
    vec4(-0.7, -0.5,  0.10,  6.0),   // wind chop 2
    vec4( 0.4, -0.8,  0.08,  4.0)    // ripple
);

const float waveAmplitudes[WAVE_COUNT] = float[](
    1.2, 0.8, 0.5, 0.3, 0.15, 0.08
);

const float waveSpeeds[WAVE_COUNT] = float[](
    1.0, 1.3, 0.9, 1.6, 2.0, 2.5
);

// ============================================================
// Gerstner Wave Evaluation
// ============================================================

struct WaveResult {
    vec3 position;
    vec3 normal;
    float foam;
};

WaveResult evaluateGerstnerWaves(vec2 xz) {
    vec3 pos = vec3(xz.x, 0.0, xz.y);
    vec3 tangent = vec3(1.0, 0.0, 0.0);
    vec3 binormal = vec3(0.0, 0.0, 1.0);
    float foamFactor = 0.0;

    for (int i = 0; i < WAVE_COUNT; ++i) {
        vec2 dir = normalize(waves[i].xy);
        float steepness = waves[i].z;
        float wavelength = waves[i].w;
        float amplitude = waveAmplitudes[i];
        float speed = waveSpeeds[i];

        float k = 2.0 * 3.14159265 / wavelength;
        float c = sqrt(9.81 / k);       // phase velocity (deep water dispersion)
        float f = k * (dot(dir, xz) - c * speed * time);
        float a = amplitude;
        float q = steepness / (k * a * float(WAVE_COUNT));  // Gerstner Q parameter

        float sinF = sin(f);
        float cosF = cos(f);

        // Gerstner displacement
        pos.x += q * a * dir.x * cosF;
        pos.z += q * a * dir.y * cosF;
        pos.y += a * sinF;

        // Partial derivatives for normal calculation
        float wa  = k * a;
        float s   = sinF;
        float co  = cosF;

        tangent.x -= q * dir.x * dir.x * wa * s;
        tangent.y += dir.x * wa * co;
        tangent.z -= q * dir.x * dir.y * wa * s;

        binormal.x -= q * dir.x * dir.y * wa * s;
        binormal.y += dir.y * wa * co;
        binormal.z -= q * dir.y * dir.y * wa * s;

        // Foam: accumulates at wave crests where curvature is high
        foamFactor += max(sinF, 0.0) * steepness;
    }

    WaveResult result;
    result.position = pos;
    result.normal = normalize(cross(binormal, tangent));
    result.foam = clamp(foamFactor - 0.3, 0.0, 1.0);
    return result;
}

void main() {
    // Bilinear interpolation of patch corners
    float u = gl_TessCoord.x;
    float v = gl_TessCoord.y;

    vec3 p0 = mix(tcsPosition[0], tcsPosition[1], u);
    vec3 p1 = mix(tcsPosition[3], tcsPosition[2], u);
    vec3 pos = mix(p0, p1, v);

    vec2 t0 = mix(tcsTexCoord[0], tcsTexCoord[1], u);
    vec2 t1 = mix(tcsTexCoord[3], tcsTexCoord[2], u);
    vec2 texCoord = mix(t0, t1, v);

    // Apply Gerstner wave displacement
    WaveResult wave = evaluateGerstnerWaves(pos.xz);

    fragWorldPos = wave.position;
    fragNormal = wave.normal;
    fragTexCoord = texCoord;
    fragFoam = wave.foam;

    gl_Position = viewProjection * vec4(wave.position, 1.0);
}

