#version 450

layout(location = 0) in vec2 fragTexCoord;
layout(location = 1) in vec4 fragColor;

layout(set = 0, binding = 0) uniform sampler2D texSampler;

layout(push_constant) uniform PushConstants {
    int  renderMode;    // 0 = textured, 1 = colored (no texture)
    int  effectMode;    // 0 = none, 1 = outline, 2 = shadow, 3 = glow
    vec4 outlineColor;  // outline/shadow/glow color
    float outlineWidth; // effect strength in UV space
} pc;

layout(location = 0) out vec4 outColor;

void main() {
    if (pc.renderMode == 1) {
        // Solid color mode (for backgrounds, labels)
        outColor = fragColor;
        return;
    }

    vec4 texColor = texture(texSampler, fragTexCoord);
    float alpha = texColor.a;

    if (pc.effectMode == 0) {
        // No effect — simple alpha-blended texture
        outColor = vec4(fragColor.rgb * texColor.rgb, alpha * fragColor.a);
    }
    else if (pc.effectMode == 1) {
        // Outline: sample surrounding texels, build outline from alpha difference
        vec2 texSize = vec2(textureSize(texSampler, 0));
        vec2 step = pc.outlineWidth / texSize;

        float maxAlpha = 0.0;
        // 8-tap sampling around current pixel
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2(-step.x, 0)).a);
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2( step.x, 0)).a);
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2(0, -step.y)).a);
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2(0,  step.y)).a);
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2(-step.x, -step.y)).a);
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2( step.x, -step.y)).a);
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2(-step.x,  step.y)).a);
        maxAlpha = max(maxAlpha, texture(texSampler, fragTexCoord + vec2( step.x,  step.y)).a);

        // Composite: outline behind, text in front
        float outlineAlpha = maxAlpha * (1.0 - alpha);
        vec3 color = mix(pc.outlineColor.rgb, fragColor.rgb * texColor.rgb, alpha);
        float finalAlpha = alpha * fragColor.a + outlineAlpha * pc.outlineColor.a;
        outColor = vec4(color, clamp(finalAlpha, 0.0, 1.0));
    }
    else if (pc.effectMode == 2) {
        // Drop shadow: offset sample
        vec2 texSize = vec2(textureSize(texSampler, 0));
        vec2 shadowOffset = pc.outlineWidth * vec2(2.0, 2.0) / texSize;
        float shadowAlpha = texture(texSampler, fragTexCoord - shadowOffset).a;

        float shadow = shadowAlpha * (1.0 - alpha) * pc.outlineColor.a;
        vec3 color = mix(pc.outlineColor.rgb, fragColor.rgb * texColor.rgb, alpha);
        float finalAlpha = alpha * fragColor.a + shadow;
        outColor = vec4(color, clamp(finalAlpha, 0.0, 1.0));
    }
    else if (pc.effectMode == 3) {
        // Glow: blurred surrounding alpha
        vec2 texSize = vec2(textureSize(texSampler, 0));
        vec2 step = pc.outlineWidth / texSize;

        float glowAlpha = 0.0;
        // 12-tap Gaussian-like sampling
        glowAlpha += texture(texSampler, fragTexCoord + vec2(-step.x, 0)).a * 0.15;
        glowAlpha += texture(texSampler, fragTexCoord + vec2( step.x, 0)).a * 0.15;
        glowAlpha += texture(texSampler, fragTexCoord + vec2(0, -step.y)).a * 0.15;
        glowAlpha += texture(texSampler, fragTexCoord + vec2(0,  step.y)).a * 0.15;
        glowAlpha += texture(texSampler, fragTexCoord + vec2(-step.x*2.0, 0)).a * 0.05;
        glowAlpha += texture(texSampler, fragTexCoord + vec2( step.x*2.0, 0)).a * 0.05;
        glowAlpha += texture(texSampler, fragTexCoord + vec2(0, -step.y*2.0)).a * 0.05;
        glowAlpha += texture(texSampler, fragTexCoord + vec2(0,  step.y*2.0)).a * 0.05;
        glowAlpha += texture(texSampler, fragTexCoord + vec2(-step.x, -step.y)).a * 0.05;
        glowAlpha += texture(texSampler, fragTexCoord + vec2( step.x, -step.y)).a * 0.05;
        glowAlpha += texture(texSampler, fragTexCoord + vec2(-step.x,  step.y)).a * 0.05;
        glowAlpha += texture(texSampler, fragTexCoord + vec2( step.x,  step.y)).a * 0.05;

        float glow = glowAlpha * (1.0 - alpha) * pc.outlineColor.a;
        vec3 color = mix(pc.outlineColor.rgb * glow, fragColor.rgb * texColor.rgb, alpha);
        float finalAlpha = alpha * fragColor.a + glow;
        outColor = vec4(color, clamp(finalAlpha, 0.0, 1.0));
    }
}

#version 450

layout(location = 0) in vec2 inPosition;
layout(location = 1) in vec2 inTexCoord;
layout(location = 2) in vec4 inColor;

layout(location = 0) out vec2 fragTexCoord;
layout(location = 1) out vec4 fragColor;

void main() {
    fragTexCoord = inTexCoord;
    fragColor = inColor;
    // inPosition is already in NDC [-1, 1]
    gl_Position = vec4(inPosition, 0.0, 1.0);
}

#version 450

layout(push_constant) uniform PushConstants {
    mat4 projection;
    mat4 model;
    vec4 tint;     // rgb = tint, a = opacity
} pc;

layout(set = 0, binding = 0) uniform sampler2D u_texture;

layout(location = 0) in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor;

void main() {
    vec4 texel = texture(u_texture, v_texCoord);
    fragColor  = vec4(texel.rgb * pc.tint.rgb, texel.a * pc.tint.a);
}

#version 450

layout(push_constant) uniform PushConstants {
    mat4 projection;
    mat4 model;
    vec4 tint;     // rgb = tint, a = opacity
} pc;

layout(location = 0) in vec2 a_position;
layout(location = 1) in vec2 a_texCoord;

layout(location = 0) out vec2 v_texCoord;

void main() {
    gl_Position = pc.projection * pc.model * vec4(a_position, 0.0, 1.0);
    v_texCoord  = a_texCoord;
}

#version 450

layout(push_constant) uniform Push {
    vec4 world_origin;
    ivec4 flags;        // x: shape_id (0=circle, 1=square)
} pc;

layout(location = 0) in vec2 v_uv;
layout(location = 1) in vec4 v_color;

layout(location = 0) out vec4 outColor;

void main() {
    if (pc.flags.x == 0) {
        // Circle: discard pixels outside the inscribed disc, with a soft edge.
        vec2 d = v_uv - vec2(0.5);
        float r2 = dot(d, d);
        if (r2 > 0.25) discard;
        // Optional soft edge — fade alpha near the rim.
        float fade = clamp(1.0 - r2 * 4.0, 0.0, 1.0);
        outColor = vec4(v_color.rgb, v_color.a * fade);
    } else {
        outColor = v_color;
    }
}

#version 450

layout(set = 0, binding = 0) uniform Scene {
    mat4 view;
    mat4 proj;
} scene;

layout(push_constant) uniform Push {
    vec4 world_origin;  // xyz: origin, w: world_scale (multiplier on inst_size)
    ivec4 flags;        // x: shape_id (0=circle, 1=square)
} pc;

// Per-vertex attributes (one quad shared by every particle).
layout(location = 0) in vec2 vert_pos;   // [-0.5, 0.5]^2
layout(location = 1) in vec2 vert_uv;    // [0, 1]^2

// Per-instance attributes (one set per live particle).
layout(location = 2) in vec3 inst_pos;
layout(location = 3) in float inst_size;
layout(location = 4) in vec4 inst_color;

layout(location = 0) out vec2 v_uv;
layout(location = 1) out vec4 v_color;

void main() {
    // Extract camera-aligned axes from the view matrix to make the quad
    // face the camera (cheap world-space billboard).
    vec3 right = vec3(scene.view[0][0], scene.view[1][0], scene.view[2][0]);
    vec3 up    = vec3(scene.view[0][1], scene.view[1][1], scene.view[2][1]);

    float s = inst_size * pc.world_origin.w;
    vec3 world = pc.world_origin.xyz + inst_pos
               + right * (vert_pos.x * s)
               + up    * (vert_pos.y * s);

    gl_Position = scene.proj * scene.view * vec4(world, 1.0);
    v_uv = vert_uv;
    v_color = inst_color;
}

#version 450

// ============================================================
// particle_spawn.comp
//
// Emits up to `EmitterBlock.to_spawn` new particles into the
// particle SSBO. Dead slots (lifetime_remaining <= 0) are
// claimed atomically via `counters.spawn_cursor`.
//
// Bindings match ergo::gpu_particle::ParticleSystem:
//   binding 0  ssbo  particles[]      (rw)
//   binding 1  ssbo  counters         (rw)
//   binding 2  ssbo  instances[]      (w, written by update)
//   binding 3  ubo   EmitterBlock
//   binding 4..13  curve_* 1D textures (not sampled here; update uses them)
// ============================================================

layout(local_size_x = 64, local_size_y = 1, local_size_z = 1) in;

struct Particle {
    vec3  position;
    float lifetime_remaining;
    vec3  velocity;
    float lifetime_initial;
    vec4  color;
    float size;
    float rotation;
    float atlas_frame;
    float seed;
};

layout(std430, binding = 0) buffer Particles { Particle particles[]; };

layout(std430, binding = 1) buffer Counters {
    uint alive_count;
    uint spawn_cursor;
    uint draw_count;
    uint total_emitted;
};

layout(std140, binding = 3) uniform EmitterBlock {
    float delta_time;
    float emitter_time;
    float simulation_speed;
    float _pad0;

    uint  to_spawn;
    uint  max_particles;
    uint  simulation_space;
    uint  random_seed;

    mat4  emitter_world;

    vec4  start_color;

    uint  shape;
    float cone_angle_rad;
    float cone_radius;
    float cone_radius_thickness;
    float sphere_radius;
    float _pad1_0;
    float _pad1_1;
    float _pad1_2;
    vec3  box_extents;
    float _pad2;
    vec3  shape_position;
    float _pad3;

    vec3  gravity;
    float gravity_modifier;
    float linear_damping;
    vec3  wind_direction;
    float wind_strength;
    float wind_turbulence;
    float _pad4_0;
    float _pad4_1;

    float start_lifetime_min;
    float start_lifetime_max;
    float start_speed_min;
    float start_speed_max;
    float start_size_min;
    float start_size_max;
    float start_rotation_min;
    float start_rotation_max;
} E;

// xorshift32
uint  rng_u32(inout uint state) {
    state ^= state << 13;
    state ^= state >> 17;
    state ^= state << 5;
    return state;
}
float rng01(inout uint state) {
    return float(rng_u32(state) >> 8) * (1.0 / 16777216.0);
}

vec3 sample_shape_direction(inout uint rng) {
    // Cone by default; fall through to sphere for Sphere/Hemisphere.
    if (E.shape == 3u) {                           // Cone
        float phi   = rng01(rng) * 6.28318530718;
        float ring  = mix(1.0 - E.cone_radius_thickness, 1.0, rng01(rng));
        float r     = E.cone_radius * sqrt(ring);
        float cx    = cos(phi) * r;
        float cz    = sin(phi) * r;
        float t     = tan(E.cone_angle_rad);
        vec3  dir   = normalize(vec3(cx * t, 1.0, cz * t));
        return dir;
    }
    if (E.shape == 4u) {                           // Box — velocity mostly +Y
        return vec3(rng01(rng) * 2.0 - 1.0,
                    rng01(rng),
                    rng01(rng) * 2.0 - 1.0);
    }
    if (E.shape == 5u) {                           // Circle (XZ)
        float phi = rng01(rng) * 6.28318530718;
        return vec3(cos(phi), 0.0, sin(phi));
    }
    // Sphere / hemisphere / default
    float z   = rng01(rng) * 2.0 - 1.0;
    if (E.shape == 2u) z = abs(z);                 // hemisphere
    float r   = sqrt(max(0.0, 1.0 - z * z));
    float phi = rng01(rng) * 6.28318530718;
    return vec3(cos(phi) * r, z, sin(phi) * r);
}

vec3 sample_shape_position(inout uint rng) {
    if (E.shape == 1u || E.shape == 2u) {          // Sphere / hemisphere
        vec3 d = sample_shape_direction(rng);
        return E.shape_position + d * (E.sphere_radius * pow(rng01(rng), 1.0/3.0));
    }
    if (E.shape == 4u) {                            // Box
        return E.shape_position + vec3(
            (rng01(rng) * 2.0 - 1.0) * E.box_extents.x,
            (rng01(rng) * 2.0 - 1.0) * E.box_extents.y,
            (rng01(rng) * 2.0 - 1.0) * E.box_extents.z);
    }
    if (E.shape == 3u) {                            // Cone base ring
        float phi   = rng01(rng) * 6.28318530718;
        float ring  = mix(1.0 - E.cone_radius_thickness, 1.0, rng01(rng));
        float r     = E.cone_radius * sqrt(ring);
        return E.shape_position + vec3(cos(phi) * r, 0.0, sin(phi) * r);
    }
    return E.shape_position;                        // Point / fallback
}

void main() {
    const uint tid = gl_GlobalInvocationID.x;
    if (tid >= E.to_spawn) return;

    // Claim a slot. Scan the particle buffer for a dead slot starting
    // from `spawn_cursor`. Bounded to `max_particles` iterations so we
    // never spin on a full buffer.
    uint offset = atomicAdd(spawn_cursor, 1u) % E.max_particles;
    uint slot   = offset;
    for (uint i = 0u; i < E.max_particles; ++i) {
        uint candidate = (offset + i) % E.max_particles;
        if (particles[candidate].lifetime_remaining <= 0.0) {
            slot = candidate;
            break;
        }
    }

    uint rng = E.random_seed ^ (tid * 0x9E3779B9u) ^
               floatBitsToUint(E.emitter_time * 1000.0);

    // Sample start values.
    float life  = mix(E.start_lifetime_min, E.start_lifetime_max, rng01(rng));
    float speed = mix(E.start_speed_min,    E.start_speed_max,    rng01(rng));
    float size  = mix(E.start_size_min,     E.start_size_max,     rng01(rng));
    float rot   = mix(E.start_rotation_min, E.start_rotation_max, rng01(rng));

    vec3 local_pos = sample_shape_position(rng);
    vec3 local_dir = sample_shape_direction(rng);

    // Emitter transform: row-vector convention (v * M), so translation
    // sits in row 3 of `emitter_world` (matches Ergo's Float4x4).
    mat4 W = E.emitter_world;
    vec4 wp = vec4(local_pos, 1.0) * W;
    vec3 wd = (vec4(local_dir, 0.0) * W).xyz;

    particles[slot].position           = wp.xyz;
    particles[slot].lifetime_remaining = life;
    particles[slot].velocity           = normalize(wd) * speed;
    particles[slot].lifetime_initial   = life;
    particles[slot].color              = E.start_color;
    particles[slot].size               = size;
    particles[slot].rotation           = rot;
    particles[slot].atlas_frame        = 0.0;
    particles[slot].seed               = rng01(rng);

    atomicAdd(total_emitted, 1u);
}

#version 450

// ============================================================
// particle_update.comp
//
// Advances every particle (alive or dead) by `delta_time`, applies
// forces, samples over-lifetime curves, and emits an `InstanceData`
// record for the live ones. `counters.alive_count` / `draw_count`
// are reset in this pass via an atomic compaction.
// ============================================================

layout(local_size_x = 64, local_size_y = 1, local_size_z = 1) in;

struct Particle {
    vec3  position;
    float lifetime_remaining;
    vec3  velocity;
    float lifetime_initial;
    vec4  color;
    float size;
    float rotation;
    float atlas_frame;
    float seed;
};

struct InstanceData {
    vec3  position;
    float size;
    vec4  color;
    float rotation;
    float atlas_frame;
    float _pad0;
    float _pad1;
};

layout(std430, binding = 0) buffer Particles { Particle    particles[]; };
layout(std430, binding = 1) buffer Counters {
    uint alive_count;
    uint spawn_cursor;
    uint draw_count;
    uint total_emitted;
};
layout(std430, binding = 2) buffer Instances { InstanceData instances[]; };

layout(std140, binding = 3) uniform EmitterBlock {
    float delta_time;
    float emitter_time;
    float simulation_speed;
    float _pad0;

    uint  to_spawn;
    uint  max_particles;
    uint  simulation_space;
    uint  random_seed;

    mat4  emitter_world;

    vec4  start_color;

    uint  shape;
    float cone_angle_rad;
    float cone_radius;
    float cone_radius_thickness;
    float sphere_radius;
    float _pad1_0;
    float _pad1_1;
    float _pad1_2;
    vec3  box_extents;
    float _pad2;
    vec3  shape_position;
    float _pad3;

    vec3  gravity;
    float gravity_modifier;
    float linear_damping;
    vec3  wind_direction;
    float wind_strength;
    float wind_turbulence;
    float _pad4_0;
    float _pad4_1;

    float start_lifetime_min;
    float start_lifetime_max;
    float start_speed_min;
    float start_speed_max;
    float start_size_min;
    float start_size_max;
    float start_rotation_min;
    float start_rotation_max;
} E;

layout(binding =  4) uniform sampler1D curve_size;
layout(binding =  5) uniform sampler1D curve_rotation;
layout(binding =  6) uniform sampler1D curve_color_r;
layout(binding =  7) uniform sampler1D curve_color_g;
layout(binding =  8) uniform sampler1D curve_color_b;
layout(binding =  9) uniform sampler1D curve_color_a;
layout(binding = 10) uniform sampler1D curve_atlas_frame;
layout(binding = 11) uniform sampler1D curve_velocity_x;
layout(binding = 12) uniform sampler1D curve_velocity_y;
layout(binding = 13) uniform sampler1D curve_velocity_z;

float sample_curve_at(sampler1D s, float age01) {
    return texture(s, clamp(age01, 0.0, 1.0)).r;
}

uint rng_u32(inout uint state) {
    state ^= state << 13;
    state ^= state >> 17;
    state ^= state << 5;
    return state;
}
float rng01(inout uint state) {
    return float(rng_u32(state) >> 8) * (1.0 / 16777216.0);
}

void main() {
    const uint idx = gl_GlobalInvocationID.x;
    if (idx == 0u) {
        alive_count = 0u;
        draw_count  = 0u;
    }
    barrier();

    if (idx >= E.max_particles) return;

    Particle p = particles[idx];
    if (p.lifetime_remaining <= 0.0) return;

    const float dt = E.delta_time;

    // Age in 0..1.
    float age01 = (p.lifetime_initial > 0.0)
                ? 1.0 - clamp(p.lifetime_remaining / p.lifetime_initial, 0.0, 1.0)
                : 0.0;

    // Forces.
    vec3 v = p.velocity;
    v += E.gravity * E.gravity_modifier * dt;
    if (E.wind_strength > 0.0) {
        v += normalize(E.wind_direction) * (E.wind_strength * dt);
    }
    float damp = clamp(1.0 - E.linear_damping * dt, 0.0, 1.0);
    v *= damp;

    // Over-lifetime velocity curve (evaluated as a per-axis multiplier
    // delta so the shader doesn't need bounds-checking).
    v.x += sample_curve_at(curve_velocity_x, age01) * dt;
    v.y += sample_curve_at(curve_velocity_y, age01) * dt;
    v.z += sample_curve_at(curve_velocity_z, age01) * dt;

    // Integrate.
    p.position += v * dt;
    p.velocity = v;
    p.lifetime_remaining -= dt;

    // Over-lifetime modifiers.
    p.size       *= sample_curve_at(curve_size, age01);
    p.rotation   += sample_curve_at(curve_rotation, age01) * dt;
    p.atlas_frame = sample_curve_at(curve_atlas_frame, age01);
    float cr = sample_curve_at(curve_color_r, age01);
    float cg = sample_curve_at(curve_color_g, age01);
    float cb = sample_curve_at(curve_color_b, age01);
    float ca = sample_curve_at(curve_color_a, age01);
    if (cr > 0.0 || cg > 0.0 || cb > 0.0 || ca > 0.0) {
        p.color = vec4(cr, cg, cb, ca);
    }

    particles[idx] = p;

    if (p.lifetime_remaining > 0.0) {
        uint out_idx = atomicAdd(alive_count, 1u);
        atomicAdd(draw_count, 1u);
        instances[out_idx].position    = p.position;
        instances[out_idx].size        = p.size;
        instances[out_idx].color       = p.color;
        instances[out_idx].rotation    = p.rotation;
        instances[out_idx].atlas_frame = p.atlas_frame;
    }
}
